SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A metallic rod of length 1 m moves at 5 m/s perpendicular to a magnetic field of 0.4 T. The EMF developed across the rod is:", "explanation": "Motional EMF ε = Bvl = 0.4 × 5 × 1 = 2 V. The rod cuts magnetic field lines as it moves, and the Lorentz force on free electrons creates a potential difference across its ends.", "correct_answer": "B", "concept_tags": ["motional-emf", "numerical-problem", "conducting-rod"], "payload": {"question_id": "cuet-phy-emi-faraday-15", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "0.2 V", "is_correct": false}, {"key": "B", "value": "2 V", "is_correct": true}, {"key": "C", "value": "20 V", "is_correct": false}, {"key": "D", "value": "0.4 V", "is_correct": false}], "elimination_hints": ["ε = Bvl = 0.4 × 5 × 1. Simply multiply the three values.", "0.2 V would result from using v = 0.5 m/s instead of 5 m/s.", "0.4 V is just the value of B, not the EMF."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A rod moves parallel to a uniform magnetic field. The EMF induced in the rod is:", "explanation": "When a rod moves parallel to the magnetic field, v is parallel to B. The Lorentz force on electrons F = qv × B = 0 (since sin0° = 0). No charge separation occurs, so no EMF is induced. EMF is induced only when the velocity has a component perpendicular to B.", "correct_answer": "A", "concept_tags": ["motional-emf", "parallel-motion", "zero-emf"], "payload": {"question_id": "cuet-phy-emi-faraday-16", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "understand", "options": [{"key": "A", "value": "Zero", "is_correct": true}, {"key": "B", "value": "Bvl", "is_correct": false}, {"key": "C", "value": "Bvl/2", "is_correct": false}, {"key": "D", "value": "2Bvl", "is_correct": false}], "elimination_hints": ["The cross product v × B = 0 when v is parallel to B (sin0° = 0).", "For EMF to be induced, the rod must cut magnetic field lines — parallel motion doesn''t cut any.", "Bvl applies only when v is perpendicular to both B and the rod."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A metallic rod of length l is rotated about one end with angular velocity ω in a uniform magnetic field B perpendicular to the plane of rotation. The EMF induced between the ends of the rod is:", "explanation": "Consider a small element dx at distance x from the pivot. Its velocity is v = ωx. The EMF across this element is dε = Bvdx = Bωx dx. Integrating from 0 to l: ε = Bω∫₀ˡ x dx = Bωl²/2 = (1/2)Bωl².", "correct_answer": "C", "concept_tags": ["rotating-rod", "motional-emf", "integration"], "payload": {"question_id": "cuet-phy-emi-faraday-17", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "Bωl", "is_correct": false}, {"key": "B", "value": "Bωl²", "is_correct": false}, {"key": "C", "value": "(1/2)Bωl²", "is_correct": true}, {"key": "D", "value": "2Bωl²", "is_correct": false}], "elimination_hints": ["Each element at distance x has velocity ωx, not ωl — you must integrate.", "Integration of x from 0 to l gives l²/2, hence the factor of 1/2.", "Bωl² would be the answer if every part of the rod moved at speed ωl."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A metallic rod of length 0.5 m is rotated about one end at 2 rev/s in a perpendicular magnetic field of 0.1 T. The EMF induced between the ends is approximately:", "explanation": "ω = 2πf = 2π × 2 = 4π rad/s. EMF = (1/2)Bωl² = (1/2) × 0.1 × 4π × (0.5)² = (1/2) × 0.1 × 4π × 0.25 = 0.05π ≈ 0.157 V ≈ 0.16 V.", "correct_answer": "B", "concept_tags": ["rotating-rod", "numerical-problem", "rpm-conversion"], "payload": {"question_id": "cuet-phy-emi-faraday-18", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "0.05 V", "is_correct": false}, {"key": "B", "value": "0.16 V", "is_correct": true}, {"key": "C", "value": "0.50 V", "is_correct": false}, {"key": "D", "value": "1.57 V", "is_correct": false}], "elimination_hints": ["Convert rev/s to rad/s: ω = 2π × 2 = 4π rad/s.", "Use ε = (1/2)Bωl² = (1/2)(0.1)(4π)(0.25) = 0.05π ≈ 0.157 V.", "1.57 V results from forgetting the factor of 1/2 and using l instead of l²."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A rectangular coil of area A having N turns is rotated at f revolutions per second in a uniform magnetic field B. The maximum value of the induced EMF is:", "explanation": "When a coil rotates in a magnetic field, Φ = NBA cos(ωt) = NBA cos(2πft). The induced EMF ε = −dΦ/dt = NBA(2πf)sin(2πft). The maximum value of EMF is ε₀ = NBA(2πf) = 2πfNBA.", "correct_answer": "D", "concept_tags": ["ac-generator", "peak-emf", "rotating-coil"], "payload": {"question_id": "cuet-phy-emi-faraday-19", "subtopic": "AC generator", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "NBAf", "is_correct": false}, {"key": "B", "value": "NBA/f", "is_correct": false}, {"key": "C", "value": "πfNBA", "is_correct": false}, {"key": "D", "value": "2πfNBA", "is_correct": true}], "elimination_hints": ["Differentiating cos(2πft) gives a factor of 2πf, not just f.", "NBAf is missing the 2π factor from the angular frequency.", "πfNBA is off by a factor of 2 — ω = 2πf, not πf."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an AC generator, the EMF is maximum when the plane of the coil is:", "explanation": "The flux Φ = BA cosθ where θ is the angle between B and the area vector. EMF = −dΦ/dt is maximum when dΦ/dt is maximum, which occurs when cos(θ) is changing most rapidly, i.e., when θ = 90°. At this position, the plane of the coil is parallel to the magnetic field and the flux through it is zero.", "correct_answer": "A", "concept_tags": ["ac-generator", "peak-emf", "coil-orientation"], "payload": {"question_id": "cuet-phy-emi-faraday-20", "subtopic": "AC generator", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "understand", "options": [{"key": "A", "value": "Parallel to the magnetic field", "is_correct": true}, {"key": "B", "value": "Perpendicular to the magnetic field", "is_correct": false}, {"key": "C", "value": "At 45° to the magnetic field", "is_correct": false}, {"key": "D", "value": "At 60° to the magnetic field", "is_correct": false}], "elimination_hints": ["When the coil is perpendicular to B, flux is maximum but its rate of change is zero — so EMF is zero.", "EMF is maximum where flux is changing fastest, which is where flux passes through zero.", "Flux is zero when the plane of the coil is parallel to B, and this is where dΦ/dt is maximum."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "An EMF is induced in a coil when:", "explanation": "An EMF is induced in a coil only when the magnetic flux through it changes with time (Faraday''s law). A steady magnetic field or constant flux, no matter how strong, does not induce any EMF.", "correct_answer": "C", "concept_tags": ["faraday-law", "flux-change", "induced-emf"], "payload": {"question_id": "cuet-phy-emi-faraday-21", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "understand", "options": [{"key": "A", "value": "It is placed in a strong magnetic field", "is_correct": false}, {"key": "B", "value": "A steady current flows through it", "is_correct": false}, {"key": "C", "value": "The magnetic flux linked with it changes", "is_correct": true}, {"key": "D", "value": "It is placed in a uniform magnetic field", "is_correct": false}], "elimination_hints": ["A strong but constant field produces zero EMF — the field must be changing.", "A steady current creates a constant magnetic field, which doesn''t induce EMF in the same coil.", "Uniform field is also constant; uniform just means same everywhere, not changing."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic flux through a coil of 10 turns changes from 0.5 Wb to 0.1 Wb in 0.1 s. If the resistance of the coil is 2 Ω, the induced current is:", "explanation": "EMF = N|ΔΦ/Δt| = 10 × |0.1 − 0.5|/0.1 = 10 × 4 = 40 V. Current I = EMF/R = 40/2 = 20 A.", "correct_answer": "C", "concept_tags": ["faraday-law", "induced-current", "ohm-law"], "payload": {"question_id": "cuet-phy-emi-faraday-22", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "2 A", "is_correct": false}, {"key": "B", "value": "10 A", "is_correct": false}, {"key": "C", "value": "20 A", "is_correct": true}, {"key": "D", "value": "40 A", "is_correct": false}], "elimination_hints": ["First find EMF: N × ΔΦ/Δt = 10 × 0.4/0.1 = 40 V.", "Then use Ohm''s law: I = EMF/R = 40/2 = 20 A.", "40 A would be the answer if R = 1 Ω."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The magnetic field in a region is given by B = B₀(t/τ), where B₀ and τ are constants. A conducting ring of radius r placed perpendicular to the field has resistance R. The induced current in the ring is:", "explanation": "Flux Φ = BA = B₀(t/τ) × πr². EMF = dΦ/dt = B₀πr²/τ (constant). Current I = EMF/R = πr²B₀/(τR). The current is constant because B increases linearly with time.", "correct_answer": "A", "concept_tags": ["faraday-law", "time-varying-field", "induced-current"], "payload": {"question_id": "cuet-phy-emi-faraday-23", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "πr²B₀/(τR)", "is_correct": true}, {"key": "B", "value": "πr²B₀τ/R", "is_correct": false}, {"key": "C", "value": "πr²B₀/(τR²)", "is_correct": false}, {"key": "D", "value": "2πrB₀/(τR)", "is_correct": false}], "elimination_hints": ["Area of the ring is πr², not 2πr (which is the circumference).", "Differentiating t/τ with respect to t gives 1/τ, so τ appears in the denominator.", "R appears in the denominator through Ohm''s law (I = EMF/R), not as R²."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A conducting rod slides along two parallel conducting rails at constant velocity v in a uniform magnetic field B directed into the page. As the rod moves, the motional EMF will:", "explanation": "The motional EMF ε = Bvl remains constant because B, v, and l are all constant. However, the current I = ε/R decreases if the resistance of the circuit increases (due to increasing rail length), or remains constant if the rail resistance is negligible compared to a fixed external resistance.", "correct_answer": "B", "concept_tags": ["motional-emf", "conducting-rod", "constant-velocity"], "payload": {"question_id": "cuet-phy-emi-faraday-24", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "understand", "options": [{"key": "A", "value": "Increase with time", "is_correct": false}, {"key": "B", "value": "Remain constant", "is_correct": true}, {"key": "C", "value": "Decrease with time", "is_correct": false}, {"key": "D", "value": "First increase then decrease", "is_correct": false}], "elimination_hints": ["EMF = Bvl — none of these quantities change with time if v is constant.", "Don''t confuse EMF with current. Current may change if resistance changes, but EMF stays constant.", "The area swept per unit time is constant (v × l), so dΦ/dt = Bvl is constant."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A wheel with 10 metallic spokes each 0.5 m long is rotated at 120 rpm in a magnetic field of 0.4 T perpendicular to the plane of the wheel. The EMF induced between the axle and the rim of the wheel is:", "explanation": "Each spoke acts as a rod rotating about one end. ω = 2π × 120/60 = 4π rad/s. EMF per spoke = (1/2)Bωl² = (1/2)(0.4)(4π)(0.25) = 0.2π ≈ 0.628 V. All spokes are in parallel between axle and rim, so the net EMF equals the EMF of one spoke ≈ 0.628 V.", "correct_answer": "C", "concept_tags": ["rotating-rod", "spoked-wheel", "parallel-emf"], "payload": {"question_id": "cuet-phy-emi-faraday-25", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "6.28 V", "is_correct": false}, {"key": "B", "value": "3.14 V", "is_correct": false}, {"key": "C", "value": "0.628 V", "is_correct": true}, {"key": "D", "value": "62.8 V", "is_correct": false}], "elimination_hints": ["All spokes are in parallel — the EMF is that of one spoke, not the sum.", "ω = 2π × 2 = 4π rad/s (120 rpm = 2 rps).", "6.28 V would result from multiplying by the number of spokes, which is incorrect for parallel connections."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A rectangular loop of sides 10 cm and 5 cm is moved out of a uniform magnetic field of 0.5 T at a speed of 2 m/s. The EMF induced while the loop is partly inside the field is:", "explanation": "As the loop moves out, the area inside the field decreases. The rate of area change = l × v where l is the side perpendicular to the velocity. Here l = 5 cm = 0.05 m. EMF = Blv = 0.5 × 0.05 × 2 = 0.05 V = 50 mV.", "correct_answer": "B", "concept_tags": ["motional-emf", "rectangular-loop", "flux-change"], "payload": {"question_id": "cuet-phy-emi-faraday-26", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "100 mV", "is_correct": false}, {"key": "B", "value": "50 mV", "is_correct": true}, {"key": "C", "value": "25 mV", "is_correct": false}, {"key": "D", "value": "10 mV", "is_correct": false}], "elimination_hints": ["Use the side perpendicular to the direction of motion (5 cm = 0.05 m).", "100 mV would result from using 10 cm (0.1 m) as the effective length.", "EMF = Blv = 0.5 × 0.05 × 2 = 0.05 V = 50 mV."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "When a rectangular loop is completely inside a uniform magnetic field and moves with constant velocity, the induced EMF is:", "explanation": "When a loop is completely inside a uniform field, the flux through it remains constant as it moves (the field is the same everywhere). Since dΦ/dt = 0, the induced EMF is zero. EMF is induced only when the loop is entering or leaving the field region.", "correct_answer": "A", "concept_tags": ["uniform-field", "zero-emf", "rectangular-loop"], "payload": {"question_id": "cuet-phy-emi-faraday-27", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "understand", "options": [{"key": "A", "value": "Zero", "is_correct": true}, {"key": "B", "value": "Bvl", "is_correct": false}, {"key": "C", "value": "2Bvl", "is_correct": false}, {"key": "D", "value": "Bvl/2", "is_correct": false}], "elimination_hints": ["Both leading and trailing edges cut field lines, but their EMFs cancel out.", "The total flux doesn''t change if the field is uniform and the entire loop is inside.", "EMF ≠ 0 only when the loop is partially inside the field (entering or leaving)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The magnetic flux through a coil perpendicular to its plane is given by Φ = 5t³ − 4t² + t (Wb). The induced EMF at t = 1 s is:", "explanation": "ε = −dΦ/dt = −(15t² − 8t + 1). At t = 1: ε = −(15 − 8 + 1) = −8 V. The magnitude of the induced EMF is 8 V.", "correct_answer": "C", "concept_tags": ["faraday-law", "differentiation", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-faraday-28", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "2 V", "is_correct": false}, {"key": "B", "value": "6 V", "is_correct": false}, {"key": "C", "value": "8 V", "is_correct": true}, {"key": "D", "value": "15 V", "is_correct": false}], "elimination_hints": ["Differentiate: dΦ/dt = 15t² − 8t + 1. At t = 1: 15 − 8 + 1 = 8.", "Don''t substitute t = 1 in Φ directly — you must differentiate first.", "2 V would be the answer for Φ at t = 1, not the EMF."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following does NOT cause electromagnetic induction?", "explanation": "Electromagnetic induction requires a change in magnetic flux through a coil. A coil stationary in a constant uniform magnetic field has constant flux, so no EMF is induced. Moving a magnet, changing current in a nearby coil, or rotating a coil in a field all cause flux changes.", "correct_answer": "D", "concept_tags": ["faraday-law", "flux-change", "conceptual"], "payload": {"question_id": "cuet-phy-emi-faraday-29", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "understand", "options": [{"key": "A", "value": "Moving a magnet towards a coil", "is_correct": false}, {"key": "B", "value": "Changing the current in a nearby coil", "is_correct": false}, {"key": "C", "value": "Rotating a coil in a magnetic field", "is_correct": false}, {"key": "D", "value": "Placing a coil in a steady uniform magnetic field", "is_correct": true}], "elimination_hints": ["A moving magnet changes the flux through the coil — induction occurs.", "Changing current changes the magnetic field, hence flux — induction occurs.", "A steady field means constant flux, so dΦ/dt = 0 and no EMF is induced."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A coil of area 0.04 m² and 100 turns is placed in a magnetic field of 0.2 T. If the coil is rotated through 180° in 0.1 s, the average induced EMF is:", "explanation": "Initial flux per turn Φ₁ = BA = 0.2 × 0.04 = 0.008 Wb. After 180° rotation, Φ₂ = −BA = −0.008 Wb. ΔΦ = Φ₂ − Φ₁ = −0.016 Wb. Average EMF = N|ΔΦ/Δt| = 100 × 0.016/0.1 = 16 V.", "correct_answer": "D", "concept_tags": ["faraday-law", "coil-rotation", "average-emf"], "payload": {"question_id": "cuet-phy-emi-faraday-30", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "0.8 V", "is_correct": false}, {"key": "B", "value": "4 V", "is_correct": false}, {"key": "C", "value": "8 V", "is_correct": false}, {"key": "D", "value": "16 V", "is_correct": true}], "elimination_hints": ["A 180° rotation reverses the flux: ΔΦ = 2BA, not just BA.", "8 V would result from using ΔΦ = BA instead of 2BA.", "Remember: N = 100 turns, and each turn contributes to the total EMF."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A circular coil of radius r is placed in a time-varying magnetic field B = B₀ sin(ωt). The maximum induced EMF in the coil is:", "explanation": "Flux Φ = BA = B₀ sin(ωt) × πr². EMF = −dΦ/dt = −B₀πr²ω cos(ωt). Maximum EMF = B₀πr²ω.", "correct_answer": "B", "concept_tags": ["faraday-law", "sinusoidal-field", "peak-emf"], "payload": {"question_id": "cuet-phy-emi-faraday-31", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "B₀πr²", "is_correct": false}, {"key": "B", "value": "B₀πr²ω", "is_correct": true}, {"key": "C", "value": "B₀πr²/ω", "is_correct": false}, {"key": "D", "value": "B₀r²ω", "is_correct": false}], "elimination_hints": ["Differentiating sin(ωt) gives ω cos(ωt), so a factor of ω appears.", "B₀πr² is just the maximum flux, not the maximum EMF.", "B₀r²ω is missing the factor of π from the area of the circle (A = πr²)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Faraday''s laws of electromagnetic induction are related to:", "explanation": "Faraday''s laws describe how a changing magnetic flux produces an induced EMF (and hence current in a closed circuit). This is the principle of conservation of energy applied to electromagnetic phenomena. The laws are fundamental to generators, transformers, and inductors.", "correct_answer": "C", "concept_tags": ["faraday-law", "conservation-of-energy"], "payload": {"question_id": "cuet-phy-emi-faraday-32", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "remember", "options": [{"key": "A", "value": "Law of conservation of charge only", "is_correct": false}, {"key": "B", "value": "Interaction between electric charges", "is_correct": false}, {"key": "C", "value": "Conservation of energy", "is_correct": true}, {"key": "D", "value": "Conservation of linear momentum", "is_correct": false}], "elimination_hints": ["Faraday''s laws, together with Lenz''s law, ensure energy conservation in electromagnetic induction.", "Interaction between charges is described by Coulomb''s law, not Faraday''s law.", "Conservation of momentum governs collisions and forces, not electromagnetic induction."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A copper ring is held horizontally and a bar magnet is dropped through the ring with its length along the axis of the ring. The acceleration of the falling magnet is:", "explanation": "As the magnet falls through the ring, the changing flux induces a current in the ring (Lenz''s law). This current creates a magnetic field that opposes the magnet''s motion, exerting a retarding force. So the net downward force is less than mg, and the acceleration is less than g.", "correct_answer": "B", "concept_tags": ["lenz-law", "falling-magnet", "retarding-force"], "payload": {"question_id": "cuet-phy-emi-faraday-33", "subtopic": "Lenz''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "Equal to g", "is_correct": false}, {"key": "B", "value": "Less than g", "is_correct": true}, {"key": "C", "value": "Greater than g", "is_correct": false}, {"key": "D", "value": "Zero", "is_correct": false}], "elimination_hints": ["If the ring were non-conducting (no current), the magnet would fall with acceleration g.", "Lenz''s law causes opposition, which decelerates the magnet, making a < g.", "The magnet does not stop (a ≠ 0) — it just falls slower than free fall."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two identical bar magnets are dropped simultaneously through two identical metallic rings — one made of copper and the other with a narrow cut (broken ring). Which magnet reaches the ground first?", "explanation": "The magnet through the broken ring reaches the ground first. The broken ring cannot sustain a continuous current (the gap prevents it), so there is no opposing force on the magnet. The magnet through the intact copper ring experiences a retarding force due to induced eddy currents (Lenz''s law) and falls slower.", "correct_answer": "B", "concept_tags": ["lenz-law", "broken-ring", "eddy-currents"], "payload": {"question_id": "cuet-phy-emi-faraday-34", "subtopic": "Lenz''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "analyze", "options": [{"key": "A", "value": "The magnet through the copper ring", "is_correct": false}, {"key": "B", "value": "The magnet through the broken ring", "is_correct": true}, {"key": "C", "value": "Both reach at the same time", "is_correct": false}, {"key": "D", "value": "Neither reaches the ground", "is_correct": false}], "elimination_hints": ["A broken ring cannot sustain eddy currents — there''s no complete conducting path.", "Without current, there''s no magnetic opposition, so the magnet falls freely.", "The intact ring opposes the magnet''s motion (Lenz''s law), slowing it down."]}}]'::jsonb, 'deploy-2026-03-05-b06');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A coil of 500 turns is placed in a magnetic field. The flux through the coil changes at a steady rate from 2 × 10⁻³ Wb to 8 × 10⁻³ Wb in 5 s. The induced EMF in the coil is:", "explanation": "EMF = N|ΔΦ/Δt| = 500 × |8 × 10⁻³ − 2 × 10⁻³|/5 = 500 × 6 × 10⁻³/5 = 500 × 1.2 × 10⁻³ = 0.6 V.", "correct_answer": "B", "concept_tags": ["faraday-law", "numerical-problem", "average-emf"], "payload": {"question_id": "cuet-phy-emi-faraday-35", "subtopic": "Faraday''s law", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "0.3 V", "is_correct": false}, {"key": "B", "value": "0.6 V", "is_correct": true}, {"key": "C", "value": "1.2 V", "is_correct": false}, {"key": "D", "value": "3.0 V", "is_correct": false}], "elimination_hints": ["ΔΦ = (8 − 2) × 10⁻³ = 6 × 10⁻³ Wb.", "ΔΦ/Δt = 6 × 10⁻³/5 = 1.2 × 10⁻³ V per turn.", "Multiply by N = 500: EMF = 500 × 1.2 × 10⁻³ = 0.6 V."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A conducting rod PQ of length l is moving with velocity v in a uniform magnetic field B directed into the page. The end P of the rod is at higher potential if:", "explanation": "Using the Lorentz force F = qv × B on positive charges in the rod: if the rod moves to the right and B is into the page, the force on positive charges is from Q to P (upward). So positive charges accumulate at P, making P at higher potential. This follows from the right-hand rule or F = qv × B.", "correct_answer": "A", "concept_tags": ["motional-emf", "lorentz-force", "potential-difference"], "payload": {"question_id": "cuet-phy-emi-faraday-36", "subtopic": "motional EMF", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "analyze", "options": [{"key": "A", "value": "The rod moves to the right with P at the top", "is_correct": true}, {"key": "B", "value": "The rod moves to the left with P at the top", "is_correct": false}, {"key": "C", "value": "The rod moves upward", "is_correct": false}, {"key": "D", "value": "The rod is stationary", "is_correct": false}], "elimination_hints": ["If the rod is stationary, there is no motional EMF — no potential difference.", "Use F = qv × B to determine the direction of force on positive charges.", "Reversing the direction of v reverses the force direction and hence which end is at higher potential."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An AC generator produces an EMF ε = 200 sin(100πt) V. The maximum EMF and frequency of the generator are:", "explanation": "Comparing with ε = ε₀ sin(ωt): ε₀ = 200 V and ω = 100π rad/s. Frequency f = ω/(2π) = 100π/(2π) = 50 Hz.", "correct_answer": "C", "concept_tags": ["ac-generator", "peak-emf", "frequency"], "payload": {"question_id": "cuet-phy-emi-faraday-37", "subtopic": "AC generator", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "200 V, 100 Hz", "is_correct": false}, {"key": "B", "value": "100 V, 50 Hz", "is_correct": false}, {"key": "C", "value": "200 V, 50 Hz", "is_correct": true}, {"key": "D", "value": "200 V, 100π Hz", "is_correct": false}], "elimination_hints": ["The coefficient of sin gives ε₀ = 200 V directly.", "ω = 100π rad/s; frequency f = ω/(2π) = 50 Hz, not 100 Hz.", "100π Hz would mean ω = 2π × 100π = 200π² rad/s, which is incorrect."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A coil of 50 turns and area 800 cm² is rotating at 60 rpm about an axis perpendicular to a field of 0.05 T. The maximum EMF induced in the coil is approximately:", "explanation": "ε₀ = NBAω. N = 50, B = 0.05 T, A = 800 cm² = 0.08 m², ω = 2π × 60/60 = 2π rad/s. ε₀ = 50 × 0.05 × 0.08 × 2π = 50 × 0.004 × 2π = 0.2 × 2π = 0.4π ≈ 1.26 V.", "correct_answer": "B", "concept_tags": ["ac-generator", "numerical-problem", "peak-emf"], "payload": {"question_id": "cuet-phy-emi-faraday-38", "subtopic": "AC generator", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "0.4 V", "is_correct": false}, {"key": "B", "value": "1.26 V", "is_correct": true}, {"key": "C", "value": "4.0 V", "is_correct": false}, {"key": "D", "value": "12.6 V", "is_correct": false}], "elimination_hints": ["Convert area: 800 cm² = 800 × 10⁻⁴ m² = 0.08 m².", "Convert rpm to rad/s: 60 rpm = 1 rps = 2π rad/s.", "0.4 V is the value without the 2π factor from ω."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an AC generator, the EMF is zero when the angle between the plane of the coil and the magnetic field is:", "explanation": "EMF = NBAω sin(θ), where θ is the angle between the area vector (normal to the coil plane) and B. EMF = 0 when sin(θ) = 0, i.e., θ = 0° or 180°. At θ = 0°, the plane of the coil is perpendicular to B (area vector parallel to B), and flux is maximum.", "correct_answer": "B", "concept_tags": ["ac-generator", "zero-emf", "coil-orientation"], "payload": {"question_id": "cuet-phy-emi-faraday-39", "subtopic": "AC generator", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "understand", "options": [{"key": "A", "value": "0°", "is_correct": false}, {"key": "B", "value": "90°", "is_correct": true}, {"key": "C", "value": "45°", "is_correct": false}, {"key": "D", "value": "30°", "is_correct": false}], "elimination_hints": ["EMF ∝ sin(θ) where θ is between area vector and B. When the plane of the coil is perpendicular to B, the angle between the plane and B is 90° and the area vector is parallel to B (θ = 0°), giving sin(0°) = 0.", "When the plane of the coil makes 90° with B, the area vector is parallel to B, giving maximum flux but zero rate of change.", "The EMF is zero when flux is at its maximum or minimum value."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-faraday", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A square coil of side 10 cm and 20 turns is rotated about its vertical diagonal in a horizontal magnetic field of 0.5 T. If the angular speed of rotation is 300 rad/s, the maximum EMF induced is:", "explanation": "For a square coil rotating about its diagonal, the effective area swept by each half is the full area of the square. A = (0.1)² = 0.01 m². ε₀ = NBAω = 20 × 0.5 × 0.01 × 300 = 30 V.", "correct_answer": "C", "concept_tags": ["ac-generator", "rotating-coil", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-faraday-40", "subtopic": "AC generator", "topic_name": "Faraday''s Laws of EMI", "bloom_level": "apply", "options": [{"key": "A", "value": "15 V", "is_correct": false}, {"key": "B", "value": "20 V", "is_correct": false}, {"key": "C", "value": "30 V", "is_correct": true}, {"key": "D", "value": "60 V", "is_correct": false}], "elimination_hints": ["Area of the square = (0.1)² = 0.01 m². Use the full area, not half.", "ε₀ = NBAω = 20 × 0.5 × 0.01 × 300 = 30 V.", "15 V would result from using half the area (0.005 m²)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Self-inductance of a coil is defined as:", "explanation": "Self-inductance L is the ratio of total magnetic flux linkage (NΦ) to the current I flowing through the coil: L = NΦ/I. It measures a coil''s ability to oppose changes in current through it by inducing a back-EMF. The SI unit of self-inductance is henry (H).", "correct_answer": "B", "concept_tags": ["self-inductance", "definition", "flux-linkage"], "payload": {"question_id": "cuet-phy-emi-inductance-01", "subtopic": "self-inductance definition", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "L = Φ/NI", "is_correct": false}, {"key": "B", "value": "L = NΦ/I", "is_correct": true}, {"key": "C", "value": "L = NI/Φ", "is_correct": false}, {"key": "D", "value": "L = I/NΦ", "is_correct": false}], "elimination_hints": ["L has units of Wb/A = henry. NΦ/I gives Wb/A, which is correct.", "NI/Φ has units of A/Wb — the inverse of henry.", "Φ/NI gives Wb/A but divides by N unnecessarily — flux linkage is NΦ, not Φ/N."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of self-inductance is:", "explanation": "The SI unit of self-inductance is henry (H), named after Joseph Henry. 1 H = 1 Wb/A = 1 V·s/A = 1 kg·m²·s⁻²·A⁻². A coil has an inductance of 1 henry if a current of 1 A produces a flux linkage of 1 Wb through it.", "correct_answer": "A", "concept_tags": ["self-inductance", "SI-unit", "henry"], "payload": {"question_id": "cuet-phy-emi-inductance-02", "subtopic": "self-inductance definition", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "Henry (H)", "is_correct": true}, {"key": "B", "value": "Weber (Wb)", "is_correct": false}, {"key": "C", "value": "Tesla (T)", "is_correct": false}, {"key": "D", "value": "Farad (F)", "is_correct": false}], "elimination_hints": ["Weber is the unit of magnetic flux, not inductance.", "Tesla is the unit of magnetic field strength.", "Farad is the unit of capacitance, not inductance."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The self-induced EMF in a coil is given by:", "explanation": "When current through an inductor changes, the self-induced EMF (back-EMF) is ε = −L(dI/dt). The negative sign indicates the EMF opposes the change in current (Lenz''s law). L is the self-inductance of the coil.", "correct_answer": "C", "concept_tags": ["self-inductance", "back-emf", "rate-of-change"], "payload": {"question_id": "cuet-phy-emi-inductance-03", "subtopic": "self-induced EMF", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "ε = LI", "is_correct": false}, {"key": "B", "value": "ε = L/I", "is_correct": false}, {"key": "C", "value": "ε = −L(dI/dt)", "is_correct": true}, {"key": "D", "value": "ε = −LI²/2", "is_correct": false}], "elimination_hints": ["LI has units of H·A = Wb, which is flux, not EMF (volts).", "LI²/2 has units of H·A² = joules — that''s the energy stored in an inductor.", "The EMF must involve rate of change of current, not just current itself."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The self-inductance of a long solenoid of length l, total number of turns N, and cross-sectional area A is:", "explanation": "For a solenoid with n = N/l turns per unit length, B = μ₀nI. Flux through each turn = BA = μ₀nIA. Total flux linkage = NΦ = N × μ₀nIA = μ₀N²IA/l. So L = NΦ/I = μ₀N²A/l.", "correct_answer": "B", "concept_tags": ["self-inductance", "solenoid", "formula"], "payload": {"question_id": "cuet-phy-emi-inductance-04", "subtopic": "inductance of solenoid", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "μ₀NA/l", "is_correct": false}, {"key": "B", "value": "μ₀N²A/l", "is_correct": true}, {"key": "C", "value": "μ₀N²l/A", "is_correct": false}, {"key": "D", "value": "μ₀NA²/l", "is_correct": false}], "elimination_hints": ["L depends on N² because both the flux (∝ N) and the linkage (× N) involve N.", "Increasing length l (keeping N constant) reduces n = N/l, weakening B, so l is in the denominator.", "Increasing area A increases flux through each turn, so A is in the numerator."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the number of turns in a solenoid is doubled (keeping length and area the same), the self-inductance becomes:", "explanation": "L = μ₀N²A/l. If N is doubled to 2N, L'' = μ₀(2N)²A/l = 4μ₀N²A/l = 4L. Self-inductance is proportional to N², so doubling N quadruples L.", "correct_answer": "C", "concept_tags": ["self-inductance", "solenoid", "proportionality"], "payload": {"question_id": "cuet-phy-emi-inductance-05", "subtopic": "inductance of solenoid", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "Doubled", "is_correct": false}, {"key": "B", "value": "Halved", "is_correct": false}, {"key": "C", "value": "Four times", "is_correct": true}, {"key": "D", "value": "Unchanged", "is_correct": false}], "elimination_hints": ["L ∝ N². Doubling N means L ∝ (2N)² = 4N².", "If L were proportional to N (not N²), doubling N would double L.", "The N² dependence arises because both B (∝ N) and flux linkage (× N) depend on N."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A solenoid of 1000 turns, length 50 cm, and cross-sectional area 10 cm² is wound on a non-magnetic material. Its self-inductance is approximately:", "explanation": "L = μ₀N²A/l = 4π × 10⁻⁷ × (1000)² × 10 × 10⁻⁴ / 0.5 = 4π × 10⁻⁷ × 10⁶ × 10⁻³ / 0.5 = 4π × 10⁻⁴ / 0.5 = 8π × 10⁻⁴ ≈ 2.51 × 10⁻³ H ≈ 2.5 mH.", "correct_answer": "B", "concept_tags": ["self-inductance", "solenoid", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-inductance-06", "subtopic": "inductance of solenoid", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "0.25 mH", "is_correct": false}, {"key": "B", "value": "2.5 mH", "is_correct": true}, {"key": "C", "value": "25 mH", "is_correct": false}, {"key": "D", "value": "0.5 mH", "is_correct": false}], "elimination_hints": ["Convert units: l = 0.5 m, A = 10 × 10⁻⁴ = 10⁻³ m².", "L = 4π × 10⁻⁷ × 10⁶ × 10⁻³ / 0.5 = 8π × 10⁻⁴ ≈ 2.5 × 10⁻³ H.", "0.25 mH would be 10 times too small — likely a unit conversion error."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The self-inductance of a solenoid depends on:", "explanation": "L = μ₀N²A/l depends on geometry (N, A, l) and the medium (μ₀ or μ). It does NOT depend on the current flowing through the solenoid. Inductance is a property of the coil itself, not of the current.", "correct_answer": "D", "concept_tags": ["self-inductance", "factors", "geometry"], "payload": {"question_id": "cuet-phy-emi-inductance-07", "subtopic": "inductance of solenoid", "topic_name": "Self and Mutual Inductance", "bloom_level": "understand", "options": [{"key": "A", "value": "The current through the solenoid", "is_correct": false}, {"key": "B", "value": "The voltage across the solenoid", "is_correct": false}, {"key": "C", "value": "The resistance of the wire", "is_correct": false}, {"key": "D", "value": "The number of turns, area, and length", "is_correct": true}], "elimination_hints": ["L = μ₀N²A/l — there is no I or V in this formula.", "Current determines the magnetic field strength, but not the inductance.", "Resistance of the wire affects time constant (τ = L/R), but not L itself."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The current through an inductor of 5 H changes at the rate of 2 A/s. The magnitude of the self-induced EMF is:", "explanation": "|ε| = L|dI/dt| = 5 × 2 = 10 V. The self-induced EMF is proportional to both the inductance and the rate of change of current.", "correct_answer": "C", "concept_tags": ["self-inductance", "back-emf", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-inductance-08", "subtopic": "self-induced EMF", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "2.5 V", "is_correct": false}, {"key": "B", "value": "5 V", "is_correct": false}, {"key": "C", "value": "10 V", "is_correct": true}, {"key": "D", "value": "20 V", "is_correct": false}], "elimination_hints": ["Simply multiply L × dI/dt = 5 × 2 = 10 V.", "2.5 V would result from dividing instead of multiplying.", "The formula is ε = L(dI/dt), not ε = L/2 × (dI/dt)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Mutual inductance between two coils is defined as:", "explanation": "Mutual inductance M₁₂ is the ratio of flux linkage in coil 2 (N₂Φ₂₁) due to current I₁ in coil 1: M = N₂Φ₂₁/I₁. It measures the coupling between two coils. By Neumann''s formula, M₁₂ = M₂₁ = M.", "correct_answer": "A", "concept_tags": ["mutual-inductance", "definition", "flux-linkage"], "payload": {"question_id": "cuet-phy-emi-inductance-09", "subtopic": "mutual inductance definition", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "M = N₂Φ₂₁/I₁", "is_correct": true}, {"key": "B", "value": "M = N₂Φ₂₁ × I₁", "is_correct": false}, {"key": "C", "value": "M = I₁/(N₂Φ₂₁)", "is_correct": false}, {"key": "D", "value": "M = N₂I₁/Φ₂₁", "is_correct": false}], "elimination_hints": ["M has units of H = Wb/A. N₂Φ₂₁/I₁ gives Wb/A — correct.", "N₂Φ₂₁ × I₁ gives Wb·A, which is not henry.", "Mutual inductance relates flux linkage in one coil to current in another."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The mutual inductance between two coaxial solenoids of the same length l, where the inner solenoid has N₁ turns and area A₁, and the outer solenoid has N₂ turns, is:", "explanation": "The field inside the outer solenoid is B₂ = μ₀(N₂/l)I₂. The flux through the inner solenoid = B₂ × A₁ = μ₀(N₂/l)I₂ × A₁. Total flux linkage in inner solenoid = N₁ × μ₀(N₂/l)I₂A₁. So M = N₁Φ/I₂ = μ₀N₁N₂A₁/l.", "correct_answer": "B", "concept_tags": ["mutual-inductance", "coaxial-solenoids", "formula"], "payload": {"question_id": "cuet-phy-emi-inductance-10", "subtopic": "mutual inductance of solenoids", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "μ₀N₁N₂A₂/l", "is_correct": false}, {"key": "B", "value": "μ₀N₁N₂A₁/l", "is_correct": true}, {"key": "C", "value": "μ₀N₁N₂(A₁ + A₂)/l", "is_correct": false}, {"key": "D", "value": "μ₀(N₁ + N₂)²A₁/l", "is_correct": false}], "elimination_hints": ["The relevant area is A₁ (inner solenoid), because the flux is confined to its cross-section.", "The outer solenoid''s field is uniform inside, but only the inner area A₁ captures flux.", "M depends on N₁N₂ (product), not (N₁ + N₂)² — mutual inductance involves coupling between two separate coils."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the coefficient of coupling between two coils is k, the mutual inductance M is related to their self-inductances L₁ and L₂ by:", "explanation": "The coefficient of coupling k relates mutual inductance to self-inductances: M = k√(L₁L₂), where 0 ≤ k ≤ 1. k = 1 for perfect coupling (all flux links both coils) and k = 0 for no coupling.", "correct_answer": "C", "concept_tags": ["mutual-inductance", "coupling-coefficient", "self-inductance"], "payload": {"question_id": "cuet-phy-emi-inductance-11", "subtopic": "coupling coefficient", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "M = k(L₁ + L₂)", "is_correct": false}, {"key": "B", "value": "M = k(L₁L₂)", "is_correct": false}, {"key": "C", "value": "M = k√(L₁L₂)", "is_correct": true}, {"key": "D", "value": "M = k√(L₁ + L₂)", "is_correct": false}], "elimination_hints": ["M has units of henry. k is dimensionless, so the expression inside must have units of H.", "k(L₁L₂) has units of H², not H — taking the square root gives the correct units.", "For two identical coils (L₁ = L₂ = L), M = kL, which is consistent with M = k√(L×L)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two coils have self-inductances L₁ = 4 mH and L₂ = 9 mH. If the coefficient of coupling is 0.5, the mutual inductance is:", "explanation": "M = k√(L₁L₂) = 0.5 × √(4 × 9) = 0.5 × √36 = 0.5 × 6 = 3 mH.", "correct_answer": "B", "concept_tags": ["mutual-inductance", "coupling-coefficient", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-inductance-12", "subtopic": "coupling coefficient", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "1.5 mH", "is_correct": false}, {"key": "B", "value": "3 mH", "is_correct": true}, {"key": "C", "value": "6 mH", "is_correct": false}, {"key": "D", "value": "18 mH", "is_correct": false}], "elimination_hints": ["√(4 × 9) = √36 = 6 mH. Then multiply by k = 0.5.", "6 mH is M for k = 1 (perfect coupling).", "18 mH would result from L₁ × L₂ without taking the square root."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The EMF induced in a coil due to change of current in a neighbouring coil is given by:", "explanation": "The mutually induced EMF in coil 2 due to changing current in coil 1 is ε₂ = −M(dI₁/dt). M is the mutual inductance between the coils. The negative sign indicates the induced EMF opposes the change (Lenz''s law).", "correct_answer": "A", "concept_tags": ["mutual-inductance", "induced-emf", "rate-of-change"], "payload": {"question_id": "cuet-phy-emi-inductance-13", "subtopic": "mutual induction EMF", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "ε = −M(dI/dt)", "is_correct": true}, {"key": "B", "value": "ε = −L(dI/dt)", "is_correct": false}, {"key": "C", "value": "ε = MI", "is_correct": false}, {"key": "D", "value": "ε = MI²/2", "is_correct": false}], "elimination_hints": ["L(dI/dt) is the self-induced EMF in the same coil, not the mutually induced EMF.", "MI has units of H·A = Wb (flux), not volts.", "The EMF depends on the rate of change of current, not just the current."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The energy stored in an inductor of inductance L carrying a current I is:", "explanation": "The energy stored in the magnetic field of an inductor is U = (1/2)LI². This is analogous to the energy stored in a capacitor U = (1/2)CV². The energy is stored in the magnetic field, not in the current itself.", "correct_answer": "B", "concept_tags": ["energy-stored", "inductor", "magnetic-field-energy"], "payload": {"question_id": "cuet-phy-emi-inductance-14", "subtopic": "energy in inductor", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "LI²", "is_correct": false}, {"key": "B", "value": "(1/2)LI²", "is_correct": true}, {"key": "C", "value": "LI", "is_correct": false}, {"key": "D", "value": "(1/2)LI", "is_correct": false}], "elimination_hints": ["Analogous to capacitor energy (1/2)CV², the inductor energy has the factor 1/2.", "LI has units of H·A = Wb, not joules.", "(1/2)LI² has units of H·A² = V·s·A = J — correct for energy."]}}]'::jsonb, 'deploy-2026-03-05-b06');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An inductor of 10 H carries a current of 2 A. The energy stored in the inductor is:", "explanation": "U = (1/2)LI² = (1/2) × 10 × (2)² = (1/2) × 10 × 4 = 20 J.", "correct_answer": "C", "concept_tags": ["energy-stored", "inductor", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-inductance-15", "subtopic": "energy in inductor", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "5 J", "is_correct": false}, {"key": "B", "value": "10 J", "is_correct": false}, {"key": "C", "value": "20 J", "is_correct": true}, {"key": "D", "value": "40 J", "is_correct": false}], "elimination_hints": ["U = (1/2) × 10 × 4 = 20 J. Don''t forget to square the current.", "10 J results from forgetting to square I: (1/2) × 10 × 2 = 10.", "40 J results from omitting the factor of 1/2."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic energy density (energy per unit volume) in a region of magnetic field B is:", "explanation": "The energy stored per unit volume in a magnetic field is u = B²/(2μ₀). This is analogous to the electric energy density u = (1/2)ε₀E². For a solenoid, the total energy U = u × Volume = [B²/(2μ₀)] × Al.", "correct_answer": "A", "concept_tags": ["energy-density", "magnetic-field", "formula"], "payload": {"question_id": "cuet-phy-emi-inductance-16", "subtopic": "magnetic energy density", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "B²/(2μ₀)", "is_correct": true}, {"key": "B", "value": "B/(2μ₀)", "is_correct": false}, {"key": "C", "value": "2B²/μ₀", "is_correct": false}, {"key": "D", "value": "μ₀B²/2", "is_correct": false}], "elimination_hints": ["B/(2μ₀) has units of T/(H/m) = A/m, which is not J/m³.", "B²/(2μ₀) has units of T²/(H/m) = J/m³ — correct for energy density.", "μ₀B²/2 has units of (H/m)·T² = incorrect dimensions."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two coils of self-inductances 2 mH and 8 mH are placed so close together that the effective flux in one coil is completely linked with the other. The mutual inductance between them is:", "explanation": "For perfect coupling (k = 1), M = k√(L₁L₂) = 1 × √(2 × 8) = √16 = 4 mH.", "correct_answer": "C", "concept_tags": ["mutual-inductance", "perfect-coupling", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-inductance-17", "subtopic": "coupling coefficient", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "2 mH", "is_correct": false}, {"key": "B", "value": "3 mH", "is_correct": false}, {"key": "C", "value": "4 mH", "is_correct": true}, {"key": "D", "value": "16 mH", "is_correct": false}], "elimination_hints": ["''Completely linked'' means k = 1 (perfect coupling).", "M = √(L₁L₂) = √(2 × 8) = √16 = 4 mH.", "16 mH is L₁ × L₂ without taking the square root."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "When a soft iron core is inserted into a solenoid, its self-inductance:", "explanation": "Self-inductance L = μN²A/l, where μ = μ₀μᵣ. Soft iron has a high relative permeability (μᵣ >> 1), so inserting it increases μ and hence L increases significantly. This is why iron cores are used in inductors and transformers.", "correct_answer": "A", "concept_tags": ["self-inductance", "iron-core", "permeability"], "payload": {"question_id": "cuet-phy-emi-inductance-18", "subtopic": "effect of core material", "topic_name": "Self and Mutual Inductance", "bloom_level": "understand", "options": [{"key": "A", "value": "Increases", "is_correct": true}, {"key": "B", "value": "Decreases", "is_correct": false}, {"key": "C", "value": "Remains unchanged", "is_correct": false}, {"key": "D", "value": "Becomes zero", "is_correct": false}], "elimination_hints": ["Iron is ferromagnetic with μᵣ >> 1, which multiplies the inductance.", "L = μ₀μᵣN²A/l — increasing μᵣ directly increases L.", "Only a superconducting shield (perfect diamagnet) could reduce L toward zero."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two inductors of self-inductances L₁ and L₂ are connected in series with no mutual coupling. The equivalent inductance is:", "explanation": "When inductors are in series with no mutual coupling (M = 0), the equivalent inductance is simply L = L₁ + L₂. This is analogous to resistors in series. If there is mutual coupling, L = L₁ + L₂ ± 2M (+ for aiding, − for opposing).", "correct_answer": "A", "concept_tags": ["inductors-in-series", "equivalent-inductance", "no-coupling"], "payload": {"question_id": "cuet-phy-emi-inductance-19", "subtopic": "combination of inductors", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "L₁ + L₂", "is_correct": true}, {"key": "B", "value": "L₁L₂/(L₁ + L₂)", "is_correct": false}, {"key": "C", "value": "L₁ − L₂", "is_correct": false}, {"key": "D", "value": "√(L₁L₂)", "is_correct": false}], "elimination_hints": ["Inductors in series add directly, just like resistors in series.", "L₁L₂/(L₁ + L₂) is the formula for inductors in parallel.", "L₁ − L₂ would give negative inductance if L₂ > L₁, which is unphysical for no coupling."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two inductors of self-inductances L₁ and L₂ are connected in parallel with no mutual coupling. The equivalent inductance is:", "explanation": "For inductors in parallel (no mutual coupling): 1/L = 1/L₁ + 1/L₂, giving L = L₁L₂/(L₁ + L₂). This is analogous to resistors in parallel.", "correct_answer": "B", "concept_tags": ["inductors-in-parallel", "equivalent-inductance", "no-coupling"], "payload": {"question_id": "cuet-phy-emi-inductance-20", "subtopic": "combination of inductors", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "L₁ + L₂", "is_correct": false}, {"key": "B", "value": "L₁L₂/(L₁ + L₂)", "is_correct": true}, {"key": "C", "value": "(L₁ + L₂)/L₁L₂", "is_correct": false}, {"key": "D", "value": "L₁ + L₂ + 2M", "is_correct": false}], "elimination_hints": ["Inductors combine like resistors: parallel gives the reciprocal formula.", "L₁ + L₂ is the series combination, not parallel.", "(L₁ + L₂)/L₁L₂ = 1/L, not L itself — you need to take the reciprocal."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An inductor opposes any change in the current flowing through it. This property is called:", "explanation": "Self-induction is the property by which an inductor opposes any change in current through it. When current increases, the back-EMF opposes the increase; when current decreases, the back-EMF opposes the decrease. This is often called electrical inertia.", "correct_answer": "A", "concept_tags": ["self-induction", "back-emf", "electrical-inertia"], "payload": {"question_id": "cuet-phy-emi-inductance-21", "subtopic": "self-induction concept", "topic_name": "Self and Mutual Inductance", "bloom_level": "understand", "options": [{"key": "A", "value": "Self-induction", "is_correct": true}, {"key": "B", "value": "Mutual induction", "is_correct": false}, {"key": "C", "value": "Electromagnetic induction", "is_correct": false}, {"key": "D", "value": "Eddy current effect", "is_correct": false}], "elimination_hints": ["Mutual induction involves two separate coils, not a single coil opposing its own current change.", "Electromagnetic induction is the general phenomenon; the specific property of opposing current change is self-induction.", "Eddy currents are induced in bulk conductors, not in the coil itself."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The phenomenon of self-induction is sometimes called the ''inertia of electricity'' because:", "explanation": "Just as mechanical inertia opposes changes in velocity, self-induction opposes changes in current. An inductor resists both increase and decrease of current, analogous to how a massive object resists both acceleration and deceleration.", "correct_answer": "D", "concept_tags": ["self-induction", "electrical-inertia", "analogy"], "payload": {"question_id": "cuet-phy-emi-inductance-22", "subtopic": "self-induction concept", "topic_name": "Self and Mutual Inductance", "bloom_level": "understand", "options": [{"key": "A", "value": "It produces current in the coil", "is_correct": false}, {"key": "B", "value": "It increases the current rapidly", "is_correct": false}, {"key": "C", "value": "It stores charge in the coil", "is_correct": false}, {"key": "D", "value": "It opposes any change in the current through the coil", "is_correct": true}], "elimination_hints": ["Self-induction does not produce current — it opposes changes to existing current.", "It actually slows down rapid current changes, not increases them.", "An inductor stores energy in its magnetic field, not charge."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A solenoid of length 0.5 m has 500 turns and area of cross-section 2 × 10⁻⁴ m². If a current of 3 A flows through it, the energy stored in the solenoid is approximately:", "explanation": "L = μ₀N²A/l = 4π × 10⁻⁷ × (500)² × 2 × 10⁻⁴ / 0.5 = 4π × 10⁻⁷ × 25 × 10⁴ × 2 × 10⁻⁴ / 0.5 = 4π × 10⁻⁷ × 100 = 4π × 10⁻⁵ H. Energy U = (1/2)LI² = (1/2) × 4π × 10⁻⁵ × 9 = 18π × 10⁻⁵ ≈ 5.65 × 10⁻⁴ J ≈ 0.56 mJ.", "correct_answer": "B", "concept_tags": ["energy-stored", "solenoid", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-inductance-23", "subtopic": "energy in inductor", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "0.056 mJ", "is_correct": false}, {"key": "B", "value": "0.56 mJ", "is_correct": true}, {"key": "C", "value": "5.6 mJ", "is_correct": false}, {"key": "D", "value": "56 mJ", "is_correct": false}], "elimination_hints": ["First find L, then use U = (1/2)LI².", "L = μ₀N²A/l ≈ 4π × 10⁻⁵ H ≈ 1.26 × 10⁻⁴ H.", "U = 0.5 × 1.26 × 10⁻⁴ × 9 ≈ 5.65 × 10⁻⁴ J ≈ 0.56 mJ."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The mutual inductance between two coils depends on:", "explanation": "Mutual inductance depends on: (1) the number of turns in both coils, (2) the area of cross-section, (3) the distance and orientation between the coils, (4) the medium between them (permeability). It does NOT depend on the current in either coil.", "correct_answer": "D", "concept_tags": ["mutual-inductance", "factors", "geometry"], "payload": {"question_id": "cuet-phy-emi-inductance-24", "subtopic": "factors affecting mutual inductance", "topic_name": "Self and Mutual Inductance", "bloom_level": "understand", "options": [{"key": "A", "value": "Current in either coil", "is_correct": false}, {"key": "B", "value": "Resistance of the coils", "is_correct": false}, {"key": "C", "value": "EMF applied to the coils", "is_correct": false}, {"key": "D", "value": "Geometry, number of turns, and the medium between them", "is_correct": true}], "elimination_hints": ["M = μ₀N₁N₂A/l — there is no I or R in this formula.", "Current determines the flux magnitude, but mutual inductance is a geometric property.", "EMF is a consequence of changing current, not a factor in determining M."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In an LR circuit connected to a battery of EMF ε, the time constant τ is:", "explanation": "The time constant of an LR circuit is τ = L/R. After one time constant, the current reaches (1 − 1/e) ≈ 63.2% of its maximum value ε/R. The time constant determines how quickly current builds up or decays in an inductive circuit.", "correct_answer": "A", "concept_tags": ["LR-circuit", "time-constant", "exponential-growth"], "payload": {"question_id": "cuet-phy-emi-inductance-25", "subtopic": "LR circuit", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "L/R", "is_correct": true}, {"key": "B", "value": "R/L", "is_correct": false}, {"key": "C", "value": "LR", "is_correct": false}, {"key": "D", "value": "√(LR)", "is_correct": false}], "elimination_hints": ["τ has units of time. L/R = H/Ω = (V·s/A)/(V/A) = s — correct.", "R/L has units of 1/s — the inverse of time.", "LR has units of H·Ω = V·s/A × V/A = V²s/A² — not seconds."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In an LR circuit, the current during growth is given by I = (ε/R)(1 − e^(−t/τ)). The current at t = τ is approximately:", "explanation": "At t = τ: I = (ε/R)(1 − e⁻¹) = (ε/R)(1 − 1/e) = (ε/R)(1 − 0.368) = 0.632(ε/R). So the current reaches about 63.2% of its maximum value in one time constant.", "correct_answer": "C", "concept_tags": ["LR-circuit", "current-growth", "time-constant"], "payload": {"question_id": "cuet-phy-emi-inductance-26", "subtopic": "LR circuit", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "ε/R", "is_correct": false}, {"key": "B", "value": "0.5(ε/R)", "is_correct": false}, {"key": "C", "value": "0.632(ε/R)", "is_correct": true}, {"key": "D", "value": "0.368(ε/R)", "is_correct": false}], "elimination_hints": ["ε/R is the maximum current (at t → ∞), not at t = τ.", "0.368(ε/R) = (ε/R)e⁻¹ — this is the remaining fraction after decay, not the growth value.", "1 − e⁻¹ ≈ 1 − 0.368 = 0.632, not 0.5."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an LR circuit, during the decay of current, the current is given by I = I₀e^(−Rt/L). After time t = L/R, the current reduces to:", "explanation": "At t = L/R = τ: I = I₀e⁻¹ = I₀/e ≈ 0.368I₀ = 36.8% of I₀. The current decays to about 37% of its initial value in one time constant.", "correct_answer": "B", "concept_tags": ["LR-circuit", "current-decay", "time-constant"], "payload": {"question_id": "cuet-phy-emi-inductance-27", "subtopic": "LR circuit", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "I₀/2", "is_correct": false}, {"key": "B", "value": "I₀/e", "is_correct": true}, {"key": "C", "value": "I₀/e²", "is_correct": false}, {"key": "D", "value": "Zero", "is_correct": false}], "elimination_hints": ["I₀/2 corresponds to the half-life, which is t₁/₂ = τ ln2 ≈ 0.693τ, not τ.", "At t = τ, I = I₀e⁻¹ = I₀/e ≈ 0.368I₀.", "I₀/e² corresponds to t = 2τ, not one time constant."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Eddy currents are produced in:", "explanation": "Eddy currents are circulating currents induced in bulk conducting materials (not just wires) when they experience changing magnetic flux. They are called ''eddy'' because they flow in closed loops within the conductor, like eddies in water.", "correct_answer": "C", "concept_tags": ["eddy-currents", "bulk-conductors", "induced-currents"], "payload": {"question_id": "cuet-phy-emi-inductance-28", "subtopic": "eddy currents", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "Insulating materials", "is_correct": false}, {"key": "B", "value": "Semiconductors only", "is_correct": false}, {"key": "C", "value": "Bulk conducting materials", "is_correct": true}, {"key": "D", "value": "Vacuum", "is_correct": false}], "elimination_hints": ["Insulators do not have free electrons to sustain eddy currents.", "While semiconductors can have some eddy currents, the primary and dominant effect is in conductors.", "Eddy currents require free charge carriers moving in closed loops — only conductors provide this."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Eddy currents can be minimized by:", "explanation": "Eddy currents are minimized by laminating the core — using thin sheets of metal insulated from each other. This breaks the conducting path and limits the area of eddy current loops, reducing their magnitude. This is why transformer cores are laminated.", "correct_answer": "B", "concept_tags": ["eddy-currents", "lamination", "minimization"], "payload": {"question_id": "cuet-phy-emi-inductance-29", "subtopic": "eddy currents", "topic_name": "Self and Mutual Inductance", "bloom_level": "understand", "options": [{"key": "A", "value": "Using a solid metal core", "is_correct": false}, {"key": "B", "value": "Using a laminated core", "is_correct": true}, {"key": "C", "value": "Increasing the thickness of the core", "is_correct": false}, {"key": "D", "value": "Using a core of higher conductivity", "is_correct": false}], "elimination_hints": ["A solid core provides large continuous conducting paths — maximizing eddy currents.", "Increasing thickness increases the area for eddy current loops.", "Higher conductivity means lower resistance, which increases eddy currents."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which of the following is NOT an application of eddy currents?", "explanation": "Eddy currents are used in electromagnetic braking, induction furnaces, speedometers (eddy current drag), and metal detectors. Charging a battery requires DC current from a chemical or electrical source, not eddy currents.", "correct_answer": "D", "concept_tags": ["eddy-currents", "applications", "conceptual"], "payload": {"question_id": "cuet-phy-emi-inductance-30", "subtopic": "eddy currents", "topic_name": "Self and Mutual Inductance", "bloom_level": "understand", "options": [{"key": "A", "value": "Electromagnetic braking", "is_correct": false}, {"key": "B", "value": "Induction furnace", "is_correct": false}, {"key": "C", "value": "Electric speedometer", "is_correct": false}, {"key": "D", "value": "Charging a battery", "is_correct": true}], "elimination_hints": ["Electromagnetic brakes use eddy currents to provide a retarding force.", "Induction furnaces use eddy current heating to melt metals.", "Battery charging requires a sustained DC source — eddy currents are dissipative and cannot charge batteries."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Eddy currents produce a heating effect because:", "explanation": "Eddy currents flow through the resistance of the conducting material. By Joule''s law (P = I²R), the current produces heat. This is the principle used in induction furnaces and induction cooktops.", "correct_answer": "A", "concept_tags": ["eddy-currents", "heating-effect", "joule-heating"], "payload": {"question_id": "cuet-phy-emi-inductance-31", "subtopic": "eddy currents", "topic_name": "Self and Mutual Inductance", "bloom_level": "understand", "options": [{"key": "A", "value": "They flow through a resistance producing I²R losses", "is_correct": true}, {"key": "B", "value": "They increase the magnetic field", "is_correct": false}, {"key": "C", "value": "They store energy in the magnetic field", "is_correct": false}, {"key": "D", "value": "They reduce the resistance of the conductor", "is_correct": false}], "elimination_hints": ["Eddy currents actually oppose the magnetic field change (Lenz''s law), they don''t increase it.", "Energy stored in the magnetic field is a property of inductors, not eddy currents.", "All current through a resistance dissipates energy as heat — this is Joule heating."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The mutual inductance between a straight long wire and a square loop of side a at a distance d from the wire is proportional to:", "explanation": "The magnetic field due to a long wire varies as B = μ₀I/(2πr). The flux through the square loop requires integration: Φ = ∫ₐ^(d+a) [μ₀I/(2πr)] × a dr = (μ₀Ia/2π) ln[(d+a)/d]. So M = Φ/I = (μ₀a/2π) ln[(d+a)/d], which involves ln and is not simply proportional to a power of d.", "correct_answer": "C", "concept_tags": ["mutual-inductance", "wire-and-loop", "logarithmic-dependence"], "payload": {"question_id": "cuet-phy-emi-inductance-32", "subtopic": "mutual inductance calculation", "topic_name": "Self and Mutual Inductance", "bloom_level": "analyze", "options": [{"key": "A", "value": "1/d", "is_correct": false}, {"key": "B", "value": "1/d²", "is_correct": false}, {"key": "C", "value": "ln[(d+a)/d]", "is_correct": true}, {"key": "D", "value": "d²", "is_correct": false}], "elimination_hints": ["The field of a wire varies as 1/r, so integrating over the loop area gives a logarithm.", "1/d dependence would occur only for a point or very small loop (a << d).", "The logarithmic dependence arises from integrating 1/r over the finite width of the loop."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In electromagnetic braking, the braking force is provided by:", "explanation": "In electromagnetic braking, when a conducting plate moves through a magnetic field, eddy currents are induced in the plate. By Lenz''s law, these eddy currents create a force that opposes the motion of the plate, providing the braking effect. No friction surfaces are needed.", "correct_answer": "B", "concept_tags": ["eddy-currents", "electromagnetic-braking", "lenz-law"], "payload": {"question_id": "cuet-phy-emi-inductance-33", "subtopic": "eddy currents", "topic_name": "Self and Mutual Inductance", "bloom_level": "understand", "options": [{"key": "A", "value": "Frictional force between surfaces", "is_correct": false}, {"key": "B", "value": "Force on eddy currents due to the magnetic field", "is_correct": true}, {"key": "C", "value": "Gravitational pull on the conductor", "is_correct": false}, {"key": "D", "value": "Elastic force of the spring mechanism", "is_correct": false}], "elimination_hints": ["The whole point of electromagnetic braking is that it''s frictionless — no wear and tear.", "Eddy currents in a magnetic field experience a Lorentz force that opposes motion.", "Gravity pulls downward regardless — it cannot provide braking."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two coils are connected in series aiding (fluxes add). If L₁ = 2 H, L₂ = 3 H, and M = 1 H, the equivalent inductance is:", "explanation": "For series aiding connection (fluxes in same direction): L_eq = L₁ + L₂ + 2M = 2 + 3 + 2(1) = 7 H. The mutual inductance adds 2M because the flux from each coil links with the other in the same direction.", "correct_answer": "D", "concept_tags": ["series-inductors", "mutual-inductance", "aiding-connection"], "payload": {"question_id": "cuet-phy-emi-inductance-34", "subtopic": "combination of inductors", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "4 H", "is_correct": false}, {"key": "B", "value": "5 H", "is_correct": false}, {"key": "C", "value": "6 H", "is_correct": false}, {"key": "D", "value": "7 H", "is_correct": true}], "elimination_hints": ["5 H = L₁ + L₂ ignores the mutual inductance contribution.", "6 H = L₁ + L₂ + M uses M instead of 2M.", "For series aiding: L_eq = L₁ + L₂ + 2M (the factor 2 accounts for mutual coupling in both directions)."]}}]'::jsonb, 'deploy-2026-03-05-b06');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two coils are connected in series opposing (fluxes subtract). If L₁ = 2 H, L₂ = 3 H, and M = 1 H, the equivalent inductance is:", "explanation": "For series opposing connection (fluxes in opposite directions): L_eq = L₁ + L₂ − 2M = 2 + 3 − 2(1) = 3 H.", "correct_answer": "B", "concept_tags": ["series-inductors", "mutual-inductance", "opposing-connection"], "payload": {"question_id": "cuet-phy-emi-inductance-35", "subtopic": "combination of inductors", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "1 H", "is_correct": false}, {"key": "B", "value": "3 H", "is_correct": true}, {"key": "C", "value": "5 H", "is_correct": false}, {"key": "D", "value": "7 H", "is_correct": false}], "elimination_hints": ["7 H is the series aiding result (L₁ + L₂ + 2M).", "5 H ignores mutual inductance entirely.", "For series opposing: L_eq = L₁ + L₂ − 2M = 5 − 2 = 3 H."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The dimensional formula of self-inductance is:", "explanation": "L = ε/(dI/dt). The dimensions of EMF (ε) are [ML²T⁻³A⁻¹] and dI/dt has dimensions [AT⁻¹]. So [L] = [ML²T⁻³A⁻¹]/[AT⁻¹] = [ML²T⁻²A⁻²].", "correct_answer": "C", "concept_tags": ["self-inductance", "dimensional-formula", "units"], "payload": {"question_id": "cuet-phy-emi-inductance-36", "subtopic": "dimensions of inductance", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "[ML²T⁻³A⁻²]", "is_correct": false}, {"key": "B", "value": "[ML²T⁻¹A⁻²]", "is_correct": false}, {"key": "C", "value": "[ML²T⁻²A⁻²]", "is_correct": true}, {"key": "D", "value": "[MLT⁻²A⁻²]", "is_correct": false}], "elimination_hints": ["1 H = 1 V·s/A = 1 kg·m²·s⁻²·A⁻², giving [ML²T⁻²A⁻²].", "Check: V = kg·m²·s⁻³·A⁻¹, so V·s/A = kg·m²·s⁻²·A⁻².", "[MLT⁻²A⁻²] is missing one power of L (length)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The principle of mutual induction is used in:", "explanation": "A transformer works on the principle of mutual induction. When AC flows through the primary coil, the changing magnetic flux links with the secondary coil, inducing an EMF in it. The ratio of EMFs equals the ratio of turns.", "correct_answer": "A", "concept_tags": ["mutual-induction", "transformer", "application"], "payload": {"question_id": "cuet-phy-emi-inductance-37", "subtopic": "applications of mutual induction", "topic_name": "Self and Mutual Inductance", "bloom_level": "remember", "options": [{"key": "A", "value": "Transformer", "is_correct": true}, {"key": "B", "value": "DC motor", "is_correct": false}, {"key": "C", "value": "Galvanometer", "is_correct": false}, {"key": "D", "value": "Potentiometer", "is_correct": false}], "elimination_hints": ["A DC motor uses the force on a current-carrying conductor in a magnetic field.", "A galvanometer measures current using torque on a current loop.", "A transformer requires two magnetically coupled coils — the essence of mutual induction."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "If the current through an inductor of 2 H changes from 5 A to 1 A in 0.05 s, the average EMF induced is:", "explanation": "|ε| = L|ΔI/Δt| = 2 × |1 − 5|/0.05 = 2 × 4/0.05 = 2 × 80 = 160 V.", "correct_answer": "D", "concept_tags": ["self-inductance", "average-emf", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-inductance-38", "subtopic": "self-induced EMF", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "16 V", "is_correct": false}, {"key": "B", "value": "40 V", "is_correct": false}, {"key": "C", "value": "80 V", "is_correct": false}, {"key": "D", "value": "160 V", "is_correct": true}], "elimination_hints": ["ΔI = |1 − 5| = 4 A, Δt = 0.05 s, so ΔI/Δt = 80 A/s.", "EMF = L × ΔI/Δt = 2 × 80 = 160 V.", "80 V would be the answer if L = 1 H."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The current in an inductor of self-inductance L is given by I = I₀ sin(ωt). The maximum value of the self-induced EMF is:", "explanation": "ε = −L(dI/dt) = −LI₀ω cos(ωt). The maximum value of |ε| = LI₀ω. This occurs when the current is passing through zero (rate of change is maximum).", "correct_answer": "B", "concept_tags": ["self-inductance", "sinusoidal-current", "peak-emf"], "payload": {"question_id": "cuet-phy-emi-inductance-39", "subtopic": "self-induced EMF", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "LI₀", "is_correct": false}, {"key": "B", "value": "LI₀ω", "is_correct": true}, {"key": "C", "value": "LI₀/ω", "is_correct": false}, {"key": "D", "value": "LI₀ω²", "is_correct": false}], "elimination_hints": ["Differentiating I₀ sin(ωt) gives I₀ω cos(ωt), so the factor ω appears.", "LI₀ has units of H·A = Wb, not volts.", "LI₀ω has units of H·A·s⁻¹ = V — correct for EMF."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A 100 mH inductor carries a current that increases uniformly from 0 to 10 A in 0.5 s. The power input to the inductor at the instant when the current is 5 A is:", "explanation": "dI/dt = (10 − 0)/0.5 = 20 A/s (uniform rate). EMF = L(dI/dt) = 0.1 × 20 = 2 V. Power input at I = 5 A: P = ε × I = 2 × 5 = 10 W. Alternatively, P = LI(dI/dt) = 0.1 × 5 × 20 = 10 W.", "correct_answer": "C", "concept_tags": ["inductor-power", "energy-storage", "numerical-problem"], "payload": {"question_id": "cuet-phy-emi-inductance-40", "subtopic": "energy in inductor", "topic_name": "Self and Mutual Inductance", "bloom_level": "apply", "options": [{"key": "A", "value": "1 W", "is_correct": false}, {"key": "B", "value": "5 W", "is_correct": false}, {"key": "C", "value": "10 W", "is_correct": true}, {"key": "D", "value": "20 W", "is_correct": false}], "elimination_hints": ["dI/dt = 20 A/s (constant). EMF = L × dI/dt = 0.1 × 20 = 2 V.", "Power = EMF × I = 2 × 5 = 10 W (at the instant when I = 5 A).", "5 W results from using I = 2.5 A or EMF = 1 V."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The voltage supplied by an AC source is given by V = V₀ sin(ωt). The peak value and the angular frequency of the source are:", "explanation": "Comparing with V = V₀ sin(ωt): V₀ is the peak (maximum) voltage and ω is the angular frequency in rad/s. The frequency f = ω/(2π) and time period T = 2π/ω.", "correct_answer": "A", "concept_tags": ["ac-voltage", "peak-value", "angular-frequency"], "payload": {"question_id": "cuet-phy-ac-circuits-01", "subtopic": "AC voltage representation", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "V₀ and ω", "is_correct": true}, {"key": "B", "value": "V₀/√2 and ω", "is_correct": false}, {"key": "C", "value": "V₀ and ω/(2π)", "is_correct": false}, {"key": "D", "value": "V₀√2 and 2πω", "is_correct": false}], "elimination_hints": ["V₀/√2 is the RMS value, not the peak value.", "ω/(2π) is the frequency f, not the angular frequency.", "The peak value is the coefficient of sin — directly V₀."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The RMS value of an alternating current I = I₀ sin(ωt) is:", "explanation": "The RMS (root mean square) value of a sinusoidal AC is I_rms = I₀/√2 ≈ 0.707 I₀. RMS values are used because they give the same heating effect as an equivalent DC current. AC ammeters and voltmeters read RMS values.", "correct_answer": "B", "concept_tags": ["rms-value", "alternating-current", "heating-effect"], "payload": {"question_id": "cuet-phy-ac-circuits-02", "subtopic": "RMS values", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "I₀", "is_correct": false}, {"key": "B", "value": "I₀/√2", "is_correct": true}, {"key": "C", "value": "I₀/2", "is_correct": false}, {"key": "D", "value": "2I₀/π", "is_correct": false}], "elimination_hints": ["I₀ is the peak value, not the RMS value.", "I₀/2 is neither the RMS nor the average value.", "2I₀/π is the average (mean) value, not the RMS value."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The average value of AC current over one complete cycle is:", "explanation": "For a sinusoidal AC, the average value over one complete cycle is zero because the positive and negative half-cycles are symmetric and cancel out. The average of sin(ωt) over a full period is zero.", "correct_answer": "A", "concept_tags": ["average-value", "full-cycle", "sinusoidal"], "payload": {"question_id": "cuet-phy-ac-circuits-03", "subtopic": "average values", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "Zero", "is_correct": true}, {"key": "B", "value": "I₀/√2", "is_correct": false}, {"key": "C", "value": "2I₀/π", "is_correct": false}, {"key": "D", "value": "I₀/2", "is_correct": false}], "elimination_hints": ["I₀/√2 is the RMS value, not the average over a full cycle.", "2I₀/π is the average over a half cycle (positive half only).", "The positive and negative halves of the sine wave are mirror images — they cancel exactly."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The average value of AC current over a positive half cycle is:", "explanation": "The average value over the positive half cycle is I_avg = (2/π)I₀ ≈ 0.637 I₀. This is obtained by integrating sin(ωt) from 0 to π and dividing by π: (1/π)∫₀^π I₀ sin(θ)dθ = (1/π)I₀[-cos(θ)]₀^π = 2I₀/π.", "correct_answer": "C", "concept_tags": ["average-value", "half-cycle", "integration"], "payload": {"question_id": "cuet-phy-ac-circuits-04", "subtopic": "average values", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "I₀/√2", "is_correct": false}, {"key": "B", "value": "I₀/π", "is_correct": false}, {"key": "C", "value": "2I₀/π", "is_correct": true}, {"key": "D", "value": "πI₀/2", "is_correct": false}], "elimination_hints": ["I₀/√2 is the RMS value, not the average value.", "I₀/π is half the correct answer — the integral gives 2I₀/π.", "πI₀/2 > I₀, which is impossible since the average cannot exceed the peak."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An AC voltage of peak value 200 V is connected across a resistance of 100 Ω. The RMS current in the circuit is:", "explanation": "V_rms = V₀/√2 = 200/√2 = 100√2 V. I_rms = V_rms/R = 100√2/100 = √2 A ≈ 1.414 A.", "correct_answer": "B", "concept_tags": ["rms-current", "pure-resistance", "numerical-problem"], "payload": {"question_id": "cuet-phy-ac-circuits-05", "subtopic": "purely resistive circuit", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "1 A", "is_correct": false}, {"key": "B", "value": "√2 A", "is_correct": true}, {"key": "C", "value": "2 A", "is_correct": false}, {"key": "D", "value": "2√2 A", "is_correct": false}], "elimination_hints": ["2 A = V₀/R = 200/100 — this is the peak current, not RMS.", "V_rms = 200/√2, so I_rms = (200/√2)/100 = √2 A.", "1 A would require V_rms = 100 V, but V_rms = 200/√2 ≈ 141 V."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In a purely resistive AC circuit, the phase difference between voltage and current is:", "explanation": "In a purely resistive circuit, voltage and current are in phase — they reach their maximum, minimum, and zero values simultaneously. The phase difference φ = 0°. V = V₀ sin(ωt) and I = I₀ sin(ωt), both with the same phase.", "correct_answer": "A", "concept_tags": ["pure-resistance", "phase-difference", "in-phase"], "payload": {"question_id": "cuet-phy-ac-circuits-06", "subtopic": "purely resistive circuit", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "0°", "is_correct": true}, {"key": "B", "value": "90°", "is_correct": false}, {"key": "C", "value": "45°", "is_correct": false}, {"key": "D", "value": "180°", "is_correct": false}], "elimination_hints": ["In a resistor, V = IR at every instant — both depend on I the same way.", "90° phase difference occurs in purely inductive or purely capacitive circuits.", "180° would mean V and I are always opposite, which contradicts V = IR (both positive or both negative)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In a purely inductive AC circuit, the current:", "explanation": "In a purely inductive circuit, the current lags behind the voltage by 90° (π/2 radians). This is because the inductor opposes changes in current. If V = V₀ sin(ωt), then I = I₀ sin(ωt − π/2) = −I₀ cos(ωt). The mnemonic ''ELI'' helps: EMF (E) leads current (I) in an inductor (L).", "correct_answer": "B", "concept_tags": ["pure-inductance", "phase-lag", "current-lags-voltage"], "payload": {"question_id": "cuet-phy-ac-circuits-07", "subtopic": "purely inductive circuit", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "Leads the voltage by 90°", "is_correct": false}, {"key": "B", "value": "Lags behind the voltage by 90°", "is_correct": true}, {"key": "C", "value": "Is in phase with the voltage", "is_correct": false}, {"key": "D", "value": "Leads the voltage by 45°", "is_correct": false}], "elimination_hints": ["Remember ''ELI the ICE man'': in L, E leads I (current lags).", "In phase would occur only in a purely resistive circuit.", "45° phase difference does not occur in a purely reactive circuit."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The inductive reactance of a coil of inductance L at angular frequency ω is:", "explanation": "Inductive reactance X_L = ωL = 2πfL. It has units of ohms and represents the opposition offered by an inductor to AC. X_L increases with frequency — inductors oppose high-frequency currents more.", "correct_answer": "C", "concept_tags": ["inductive-reactance", "formula", "frequency-dependence"], "payload": {"question_id": "cuet-phy-ac-circuits-08", "subtopic": "purely inductive circuit", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "L/ω", "is_correct": false}, {"key": "B", "value": "ω/L", "is_correct": false}, {"key": "C", "value": "ωL", "is_correct": true}, {"key": "D", "value": "1/(ωL)", "is_correct": false}], "elimination_hints": ["L/ω has units of H·s = Ω·s², which is not ohms.", "1/(ωL) is the capacitive reactance formula pattern, not inductive.", "X_L = ωL has units of (rad/s)(H) = (rad/s)(Ω·s) = Ω — correct."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An inductor of 1/π H is connected to a 50 Hz AC source. The inductive reactance is:", "explanation": "X_L = ωL = 2πfL = 2π × 50 × (1/π) = 100 Ω.", "correct_answer": "C", "concept_tags": ["inductive-reactance", "numerical-problem", "frequency"], "payload": {"question_id": "cuet-phy-ac-circuits-09", "subtopic": "purely inductive circuit", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "50 Ω", "is_correct": false}, {"key": "B", "value": "50π Ω", "is_correct": false}, {"key": "C", "value": "100 Ω", "is_correct": true}, {"key": "D", "value": "200 Ω", "is_correct": false}], "elimination_hints": ["X_L = 2πfL = 2π × 50 × (1/π) = 2 × 50 = 100 Ω.", "50 Ω uses ω = πf instead of 2πf.", "The π in L = 1/π cancels with the π in ω = 2πf."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In a purely capacitive AC circuit, the current:", "explanation": "In a purely capacitive circuit, current leads the voltage by 90° (π/2). The capacitor starts charging as soon as voltage is applied, so current flows first. If V = V₀ sin(ωt), then I = I₀ sin(ωt + π/2) = I₀ cos(ωt). Mnemonic: ''ICE'' — current (I) leads EMF (E) in a capacitor (C).", "correct_answer": "A", "concept_tags": ["pure-capacitance", "phase-lead", "current-leads-voltage"], "payload": {"question_id": "cuet-phy-ac-circuits-10", "subtopic": "purely capacitive circuit", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "Leads the voltage by 90°", "is_correct": true}, {"key": "B", "value": "Lags behind the voltage by 90°", "is_correct": false}, {"key": "C", "value": "Is in phase with the voltage", "is_correct": false}, {"key": "D", "value": "Lags behind the voltage by 45°", "is_correct": false}], "elimination_hints": ["Remember ''ICE'': in C, I leads E — current leads voltage.", "Lagging by 90° happens in a purely inductive circuit (ELI).", "In phase occurs only in a purely resistive circuit."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The capacitive reactance of a capacitor of capacitance C at angular frequency ω is:", "explanation": "Capacitive reactance X_C = 1/(ωC) = 1/(2πfC). It has units of ohms and represents the opposition offered by a capacitor to AC. X_C decreases with frequency — capacitors allow high-frequency currents more easily.", "correct_answer": "D", "concept_tags": ["capacitive-reactance", "formula", "frequency-dependence"], "payload": {"question_id": "cuet-phy-ac-circuits-11", "subtopic": "purely capacitive circuit", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "ωC", "is_correct": false}, {"key": "B", "value": "ω/C", "is_correct": false}, {"key": "C", "value": "C/ω", "is_correct": false}, {"key": "D", "value": "1/(ωC)", "is_correct": true}], "elimination_hints": ["ωC has units of (rad/s)(F) = (rad/s)(s/Ω) = 1/Ω — inverse of ohms, not ohms.", "1/(ωC) has units of 1/[(rad/s)(F)] = Ω — correct for reactance.", "X_C decreases with ω, so it must have ω in the denominator."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A capacitor of 10 μF is connected to a 50 Hz AC source. The capacitive reactance is approximately:", "explanation": "X_C = 1/(2πfC) = 1/(2π × 50 × 10 × 10⁻⁶) = 1/(π × 10⁻³) = 1000/π ≈ 318 Ω.", "correct_answer": "B", "concept_tags": ["capacitive-reactance", "numerical-problem", "frequency"], "payload": {"question_id": "cuet-phy-ac-circuits-12", "subtopic": "purely capacitive circuit", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "100 Ω", "is_correct": false}, {"key": "B", "value": "318 Ω", "is_correct": true}, {"key": "C", "value": "500 Ω", "is_correct": false}, {"key": "D", "value": "1000 Ω", "is_correct": false}], "elimination_hints": ["X_C = 1/(2π × 50 × 10⁻⁵) = 1/(π × 10⁻³) = 1000/π ≈ 318 Ω.", "1000 Ω would require forgetting the factor of π.", "100 Ω would result from using f = 50/(2π) instead of 50 Hz."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The inductive reactance of a coil is 200 Ω at 50 Hz. Its inductive reactance at 100 Hz will be:", "explanation": "X_L = ωL = 2πfL. Since X_L is directly proportional to frequency, doubling the frequency doubles the reactance. X_L at 100 Hz = 200 × (100/50) = 400 Ω.", "correct_answer": "C", "concept_tags": ["inductive-reactance", "frequency-dependence", "proportionality"], "payload": {"question_id": "cuet-phy-ac-circuits-13", "subtopic": "purely inductive circuit", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "100 Ω", "is_correct": false}, {"key": "B", "value": "200 Ω", "is_correct": false}, {"key": "C", "value": "400 Ω", "is_correct": true}, {"key": "D", "value": "800 Ω", "is_correct": false}], "elimination_hints": ["X_L ∝ f. Doubling f doubles X_L.", "100 Ω would result from an inverse relationship (which applies to X_C, not X_L).", "X_L does not remain 200 Ω because it is frequency-dependent."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The capacitive reactance of a capacitor is 400 Ω at 50 Hz. Its capacitive reactance at 200 Hz will be:", "explanation": "X_C = 1/(2πfC). X_C is inversely proportional to frequency. When frequency increases by a factor of 4 (50 to 200 Hz), X_C decreases by a factor of 4. X_C = 400/4 = 100 Ω.", "correct_answer": "A", "concept_tags": ["capacitive-reactance", "frequency-dependence", "inverse-proportionality"], "payload": {"question_id": "cuet-phy-ac-circuits-14", "subtopic": "purely capacitive circuit", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "100 Ω", "is_correct": true}, {"key": "B", "value": "200 Ω", "is_correct": false}, {"key": "C", "value": "400 Ω", "is_correct": false}, {"key": "D", "value": "1600 Ω", "is_correct": false}], "elimination_hints": ["X_C ∝ 1/f. Frequency increased by 4×, so X_C decreases by 4×.", "1600 Ω would result from a direct proportionality (X_C × 4), which applies to X_L, not X_C.", "X_C cannot remain 400 Ω because it depends on frequency."]}}]'::jsonb, 'deploy-2026-03-05-b06');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an AC circuit, a capacitor behaves as an open circuit for:", "explanation": "For DC (f = 0), X_C = 1/(2πfC) → ∞. An infinite reactance means no current flows — the capacitor acts as an open circuit. For very high frequencies, X_C → 0, and the capacitor acts as a short circuit.", "correct_answer": "A", "concept_tags": ["capacitive-reactance", "DC-behavior", "frequency-limit"], "payload": {"question_id": "cuet-phy-ac-circuits-15", "subtopic": "purely capacitive circuit", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "DC (zero frequency)", "is_correct": true}, {"key": "B", "value": "Very high frequency AC", "is_correct": false}, {"key": "C", "value": "50 Hz AC", "is_correct": false}, {"key": "D", "value": "All frequencies", "is_correct": false}], "elimination_hints": ["At high frequency, X_C → 0, so the capacitor acts as a short circuit, not open.", "A capacitor blocks DC because it cannot sustain a steady current — charges pile up and stop.", "At 50 Hz, the capacitor has a finite reactance and allows some current."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An inductor behaves as a short circuit for:", "explanation": "For DC (f = 0), X_L = ωL = 0. Zero reactance means the inductor offers no opposition — it acts as a short circuit (just a wire with some resistance). For very high frequencies, X_L → ∞, and the inductor acts as an open circuit.", "correct_answer": "B", "concept_tags": ["inductive-reactance", "DC-behavior", "frequency-limit"], "payload": {"question_id": "cuet-phy-ac-circuits-16", "subtopic": "purely inductive circuit", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "Very high frequency AC", "is_correct": false}, {"key": "B", "value": "DC (zero frequency)", "is_correct": true}, {"key": "C", "value": "Resonant frequency", "is_correct": false}, {"key": "D", "value": "All frequencies", "is_correct": false}], "elimination_hints": ["At high frequency, X_L = ωL is very large — the inductor acts as an open circuit.", "At f = 0 (DC), ω = 0, so X_L = 0 — the inductor acts as a plain wire.", "At resonant frequency, X_L = X_C, but X_L is not zero."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The impedance of a series LCR circuit is given by:", "explanation": "In a series LCR circuit, the impedance Z = √[R² + (X_L − X_C)²] = √[R² + (ωL − 1/(ωC))²]. The net reactance is (X_L − X_C) because V_L and V_C are 180° out of phase and partially cancel.", "correct_answer": "D", "concept_tags": ["impedance", "LCR-circuit", "formula"], "payload": {"question_id": "cuet-phy-ac-circuits-17", "subtopic": "series LCR circuit", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "R + X_L + X_C", "is_correct": false}, {"key": "B", "value": "√(R² + X_L² + X_C²)", "is_correct": false}, {"key": "C", "value": "R + (X_L − X_C)", "is_correct": false}, {"key": "D", "value": "√[R² + (X_L − X_C)²]", "is_correct": true}], "elimination_hints": ["V_R, V_L, and V_C are not in phase, so impedances don''t add linearly.", "V_L and V_C are 180° apart, so their net effect is |X_L − X_C|, not √(X_L² + X_C²).", "V_R is 90° out of phase with the net reactive voltage, requiring Pythagorean addition."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a series LCR circuit at resonance, the impedance is:", "explanation": "At resonance, X_L = X_C, so the net reactance is zero. Z = √[R² + (X_L − X_C)²] = √[R² + 0] = R. The impedance is minimum and equals the resistance. Current is maximum at resonance.", "correct_answer": "B", "concept_tags": ["resonance", "impedance", "minimum-impedance"], "payload": {"question_id": "cuet-phy-ac-circuits-18", "subtopic": "series LCR resonance", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "Zero", "is_correct": false}, {"key": "B", "value": "R", "is_correct": true}, {"key": "C", "value": "X_L + X_C", "is_correct": false}, {"key": "D", "value": "√(R² + X_L²)", "is_correct": false}], "elimination_hints": ["Zero impedance would mean infinite current — physically impossible with R present.", "At resonance, X_L = X_C cancel out, leaving only R.", "X_L + X_C is not relevant — the reactive voltages oppose each other (subtract, not add)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The resonant frequency of a series LCR circuit is:", "explanation": "At resonance, X_L = X_C, i.e., ωL = 1/(ωC). Solving: ω² = 1/(LC), so ω₀ = 1/√(LC). The resonant frequency f₀ = 1/(2π√(LC)). At this frequency, impedance is minimum and current is maximum.", "correct_answer": "A", "concept_tags": ["resonant-frequency", "LCR-circuit", "formula"], "payload": {"question_id": "cuet-phy-ac-circuits-19", "subtopic": "series LCR resonance", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "1/(2π√(LC))", "is_correct": true}, {"key": "B", "value": "2π√(LC)", "is_correct": false}, {"key": "C", "value": "1/(2πLC)", "is_correct": false}, {"key": "D", "value": "√(LC)/(2π)", "is_correct": false}], "elimination_hints": ["f₀ must decrease when L or C increases (larger L or C means lower resonant frequency).", "2π√(LC) increases with L and C — opposite to expected behavior.", "f₀ = ω₀/(2π) = 1/(2π√(LC)). The √ is crucial."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A series LCR circuit has L = 1 H, C = 1 μF, and R = 100 Ω. The resonant frequency is approximately:", "explanation": "f₀ = 1/(2π√(LC)) = 1/(2π√(1 × 10⁻⁶)) = 1/(2π × 10⁻³) = 1000/(2π) ≈ 159 Hz.", "correct_answer": "C", "concept_tags": ["resonant-frequency", "numerical-problem", "LCR-circuit"], "payload": {"question_id": "cuet-phy-ac-circuits-20", "subtopic": "series LCR resonance", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "50 Hz", "is_correct": false}, {"key": "B", "value": "100 Hz", "is_correct": false}, {"key": "C", "value": "159 Hz", "is_correct": true}, {"key": "D", "value": "1000 Hz", "is_correct": false}], "elimination_hints": ["√(LC) = √(1 × 10⁻⁶) = 10⁻³ s.", "f₀ = 1/(2π × 10⁻³) = 1000/(2π) ≈ 159 Hz.", "1000 Hz would be the answer without the 2π factor."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "At resonance in a series LCR circuit, the phase difference between voltage and current is:", "explanation": "At resonance, X_L = X_C, so the net reactance is zero. The circuit is purely resistive, and voltage and current are in phase. tan(φ) = (X_L − X_C)/R = 0, so φ = 0°.", "correct_answer": "A", "concept_tags": ["resonance", "phase-difference", "zero-phase"], "payload": {"question_id": "cuet-phy-ac-circuits-21", "subtopic": "series LCR resonance", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "0°", "is_correct": true}, {"key": "B", "value": "90°", "is_correct": false}, {"key": "C", "value": "45°", "is_correct": false}, {"key": "D", "value": "180°", "is_correct": false}], "elimination_hints": ["At resonance the circuit is purely resistive — and in a resistor, V and I are in phase.", "90° occurs in purely reactive circuits (L or C alone).", "The reactive components cancel at resonance, leaving only R."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The quality factor (Q-factor) of a series LCR circuit at resonance is:", "explanation": "The Q-factor measures the sharpness of resonance: Q = ω₀L/R = 1/(ω₀CR) = (1/R)√(L/C). A higher Q means a sharper resonance peak and greater frequency selectivity. Q also equals V_L/V_R or V_C/V_R at resonance.", "correct_answer": "D", "concept_tags": ["quality-factor", "sharpness-of-resonance", "LCR-circuit"], "payload": {"question_id": "cuet-phy-ac-circuits-22", "subtopic": "Q-factor", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "R/(ω₀L)", "is_correct": false}, {"key": "B", "value": "ω₀CR", "is_correct": false}, {"key": "C", "value": "R√(L/C)", "is_correct": false}, {"key": "D", "value": "ω₀L/R", "is_correct": true}], "elimination_hints": ["Q should increase when R decreases (sharper resonance), so R must be in the denominator.", "R/(ω₀L) is 1/Q, not Q.", "Q = ω₀L/R = (1/R)√(L/C) — both expressions are equivalent at resonance."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In a series LCR circuit, R = 10 Ω, L = 0.1 H, and C = 10 μF. The Q-factor at resonance is:", "explanation": "Q = (1/R)√(L/C) = (1/10)√(0.1/(10 × 10⁻⁶)) = (1/10)√(10⁴) = (1/10) × 100 = 10.", "correct_answer": "C", "concept_tags": ["quality-factor", "numerical-problem", "resonance"], "payload": {"question_id": "cuet-phy-ac-circuits-23", "subtopic": "Q-factor", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "1", "is_correct": false}, {"key": "B", "value": "5", "is_correct": false}, {"key": "C", "value": "10", "is_correct": true}, {"key": "D", "value": "100", "is_correct": false}], "elimination_hints": ["L/C = 0.1/(10⁻⁵) = 10⁴. √(10⁴) = 100.", "Q = 100/R = 100/10 = 10.", "100 would be the answer if R = 1 Ω."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The power dissipated in a purely inductive or purely capacitive AC circuit is:", "explanation": "In a purely inductive or purely capacitive circuit, the phase difference between V and I is 90°. Power P = V_rms × I_rms × cosφ = V_rms × I_rms × cos90° = 0. Energy is alternately stored and released, with zero net dissipation per cycle.", "correct_answer": "A", "concept_tags": ["power", "pure-reactance", "zero-power"], "payload": {"question_id": "cuet-phy-ac-circuits-24", "subtopic": "power in AC circuits", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "Zero", "is_correct": true}, {"key": "B", "value": "V_rms × I_rms", "is_correct": false}, {"key": "C", "value": "(V_rms × I_rms)/2", "is_correct": false}, {"key": "D", "value": "V_rms²/X", "is_correct": false}], "elimination_hints": ["V_rms × I_rms is the apparent power, not the real (dissipated) power.", "Power factor cosφ = cos90° = 0 for purely reactive circuits.", "Only resistance dissipates power; ideal inductors and capacitors store and return energy."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The power factor of an AC circuit is defined as:", "explanation": "Power factor = cosφ = R/Z, where φ is the phase angle between voltage and current. It determines what fraction of apparent power is actually dissipated. Power factor ranges from 0 (purely reactive) to 1 (purely resistive or at resonance).", "correct_answer": "B", "concept_tags": ["power-factor", "cos-phi", "impedance"], "payload": {"question_id": "cuet-phy-ac-circuits-25", "subtopic": "power in AC circuits", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "sinφ", "is_correct": false}, {"key": "B", "value": "cosφ", "is_correct": true}, {"key": "C", "value": "tanφ", "is_correct": false}, {"key": "D", "value": "Z/R", "is_correct": false}], "elimination_hints": ["Power = V_rms × I_rms × cosφ, so the factor is cosφ, not sinφ.", "Z/R is always ≥ 1, but power factor must be ≤ 1. It''s R/Z, not Z/R.", "tanφ = (X_L − X_C)/R gives the phase angle relationship, not the power factor."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The power factor of a series LCR circuit at resonance is:", "explanation": "At resonance, X_L = X_C, so Z = R. Power factor = R/Z = R/R = 1 (or cosφ = cos0° = 1). The circuit behaves as purely resistive, and maximum power is transferred.", "correct_answer": "D", "concept_tags": ["power-factor", "resonance", "maximum-power"], "payload": {"question_id": "cuet-phy-ac-circuits-26", "subtopic": "power in AC circuits", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "0", "is_correct": false}, {"key": "B", "value": "0.5", "is_correct": false}, {"key": "C", "value": "1/√2", "is_correct": false}, {"key": "D", "value": "1", "is_correct": true}], "elimination_hints": ["Power factor 0 means no power dissipation — that''s for purely reactive circuits.", "At resonance, the circuit is purely resistive, giving the maximum possible power factor.", "cosφ = R/Z = R/R = 1 at resonance."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In a series LR circuit, R = 30 Ω and X_L = 40 Ω. The impedance and power factor are:", "explanation": "Z = √(R² + X_L²) = √(900 + 1600) = √2500 = 50 Ω. Power factor = cosφ = R/Z = 30/50 = 0.6.", "correct_answer": "B", "concept_tags": ["impedance", "power-factor", "LR-circuit"], "payload": {"question_id": "cuet-phy-ac-circuits-27", "subtopic": "series LR circuit", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "Z = 70 Ω, cosφ = 0.43", "is_correct": false}, {"key": "B", "value": "Z = 50 Ω, cosφ = 0.6", "is_correct": true}, {"key": "C", "value": "Z = 50 Ω, cosφ = 0.8", "is_correct": false}, {"key": "D", "value": "Z = 10 Ω, cosφ = 0.3", "is_correct": false}], "elimination_hints": ["70 Ω = R + X_L — but impedances don''t add linearly (they add as vectors).", "Z = √(30² + 40²) = √(2500) = 50 Ω (a 3-4-5 right triangle scaled by 10).", "cosφ = R/Z = 30/50 = 0.6, not 40/50 = 0.8."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The average power dissipated in an AC circuit is:", "explanation": "Average power P = V_rms × I_rms × cosφ, where cosφ is the power factor. This is also called true power or real power. Only the resistive component of the circuit dissipates power.", "correct_answer": "C", "concept_tags": ["average-power", "power-factor", "AC-power"], "payload": {"question_id": "cuet-phy-ac-circuits-28", "subtopic": "power in AC circuits", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "V_rms × I_rms", "is_correct": false}, {"key": "B", "value": "V₀ × I₀", "is_correct": false}, {"key": "C", "value": "V_rms × I_rms × cosφ", "is_correct": true}, {"key": "D", "value": "V_rms × I_rms × sinφ", "is_correct": false}], "elimination_hints": ["V_rms × I_rms is the apparent power (VA), not the real power (W).", "V₀ × I₀ is neither the apparent nor the real power.", "sinφ gives the reactive power component, not the dissipated power."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The quantity V_rms × I_rms in an AC circuit is called:", "explanation": "V_rms × I_rms is called apparent power (measured in volt-amperes, VA). The real power is P = V_rms × I_rms × cosφ. The ratio of real power to apparent power is the power factor.", "correct_answer": "B", "concept_tags": ["apparent-power", "volt-ampere", "power-terminology"], "payload": {"question_id": "cuet-phy-ac-circuits-29", "subtopic": "power in AC circuits", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "Real power", "is_correct": false}, {"key": "B", "value": "Apparent power", "is_correct": true}, {"key": "C", "value": "Power factor", "is_correct": false}, {"key": "D", "value": "Reactive power", "is_correct": false}], "elimination_hints": ["Real power includes the cosφ factor: P = V_rms × I_rms × cosφ.", "Power factor is cosφ (dimensionless), not a power quantity.", "Reactive power is V_rms × I_rms × sinφ, measured in VAR."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A transformer works on the principle of:", "explanation": "A transformer works on the principle of mutual induction. An alternating current in the primary coil creates a changing magnetic flux, which links with the secondary coil and induces an EMF in it. Transformers only work with AC, not DC.", "correct_answer": "C", "concept_tags": ["transformer", "mutual-induction", "working-principle"], "payload": {"question_id": "cuet-phy-ac-circuits-30", "subtopic": "transformer", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "Self-induction", "is_correct": false}, {"key": "B", "value": "Electromagnetic force", "is_correct": false}, {"key": "C", "value": "Mutual induction", "is_correct": true}, {"key": "D", "value": "Electrostatic induction", "is_correct": false}], "elimination_hints": ["Self-induction involves a single coil, but a transformer has two separate coils.", "Electrostatic induction involves charges, not changing magnetic flux.", "The primary coil''s changing flux induces EMF in the secondary — this is mutual induction."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In an ideal transformer, the ratio of secondary EMF to primary EMF equals:", "explanation": "For an ideal transformer, ε_s/ε_p = N_s/N_p, where N_s and N_p are the number of turns in the secondary and primary coils respectively. This is the turns ratio. A step-up transformer has N_s > N_p, and a step-down transformer has N_s < N_p.", "correct_answer": "A", "concept_tags": ["transformer", "turns-ratio", "EMF-ratio"], "payload": {"question_id": "cuet-phy-ac-circuits-31", "subtopic": "transformer", "topic_name": "AC Circuits", "bloom_level": "remember", "options": [{"key": "A", "value": "N_s/N_p", "is_correct": true}, {"key": "B", "value": "N_p/N_s", "is_correct": false}, {"key": "C", "value": "(N_s/N_p)²", "is_correct": false}, {"key": "D", "value": "√(N_s/N_p)", "is_correct": false}], "elimination_hints": ["N_p/N_s is the inverse of the turns ratio (ε_p/ε_s, not ε_s/ε_p).", "(N_s/N_p)² relates to impedance transformation, not voltage transformation.", "EMF is proportional to N (more turns = more flux linkage = more EMF)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A step-up transformer has:", "explanation": "A step-up transformer increases voltage: V_s > V_p. This requires N_s > N_p (more turns in secondary). By energy conservation (for ideal transformer), P_s = P_p, so I_s < I_p — the current decreases when voltage increases.", "correct_answer": "B", "concept_tags": ["step-up-transformer", "turns-ratio", "voltage-current"], "payload": {"question_id": "cuet-phy-ac-circuits-32", "subtopic": "transformer", "topic_name": "AC Circuits", "bloom_level": "understand", "options": [{"key": "A", "value": "N_s < N_p", "is_correct": false}, {"key": "B", "value": "N_s > N_p", "is_correct": true}, {"key": "C", "value": "N_s = N_p", "is_correct": false}, {"key": "D", "value": "I_s > I_p", "is_correct": false}], "elimination_hints": ["N_s < N_p is a step-down transformer (voltage decreases).", "N_s = N_p gives a 1:1 isolation transformer.", "In a step-up transformer, voltage increases but current decreases (power is conserved)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A transformer has 200 turns in the primary and 1000 turns in the secondary. If the primary voltage is 220 V, the secondary voltage is:", "explanation": "V_s/V_p = N_s/N_p. V_s = V_p × (N_s/N_p) = 220 × (1000/200) = 220 × 5 = 1100 V.", "correct_answer": "D", "concept_tags": ["transformer", "turns-ratio", "numerical-problem"], "payload": {"question_id": "cuet-phy-ac-circuits-33", "subtopic": "transformer", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "44 V", "is_correct": false}, {"key": "B", "value": "220 V", "is_correct": false}, {"key": "C", "value": "550 V", "is_correct": false}, {"key": "D", "value": "1100 V", "is_correct": true}], "elimination_hints": ["Turns ratio = 1000/200 = 5. This is a step-up transformer.", "V_s = 220 × 5 = 1100 V.", "44 V would result from using N_p/N_s (step-down) instead of N_s/N_p."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-em-ac-circuits", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An ideal transformer has a primary voltage of 240 V and delivers 12 V to a load that draws 2 A. The primary current is:", "explanation": "For an ideal transformer, P_p = P_s. So V_p × I_p = V_s × I_s. I_p = V_s × I_s / V_p = 12 × 2 / 240 = 24/240 = 0.1 A.", "correct_answer": "A", "concept_tags": ["transformer", "power-conservation", "numerical-problem"], "payload": {"question_id": "cuet-phy-ac-circuits-34", "subtopic": "transformer", "topic_name": "AC Circuits", "bloom_level": "apply", "options": [{"key": "A", "value": "0.1 A", "is_correct": true}, {"key": "B", "value": "0.5 A", "is_correct": false}, {"key": "C", "value": "2 A", "is_correct": false}, {"key": "D", "value": "40 A", "is_correct": false}], "elimination_hints": ["Power conservation: V_p × I_p = V_s × I_s = 12 × 2 = 24 W.", "I_p = 24/240 = 0.1 A.", "Since this is a step-down transformer (240 V → 12 V), the primary current must be less than the secondary current."]}}]'::jsonb, 'deploy-2026-03-05-b06');

